{
  "name": "Al-Farā’iḍ: Islamic Inheritance Calculator",
  "description": "A comprehensive, professionally designed Islamic Inheritance Calculator based on Sunni Fiqh (Hanafi, Shafi'i, Maliki, Hanbali). Supports 20+ languages and multiple currencies.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum FiqhSchool {
  Hanafi = 'Hanafi',
  Shafi = 'Shafi',
  Maliki = 'Maliki',
  Hanbali = 'Hanbali',
  General = 'General'
}

export enum DeceasedGender {
  Male = 'Male',
  Female = 'Female'
}

export type HeirKey = 
  | 'son' | 'grandson' | 'father' | 'grandfather' 
  | 'fullBrother' | 'paternalBrother' | 'maternalBrother'
  | 'nephewFull' | 'nephewPaternal' 
  | 'uncleFull' | 'unclePaternal'
  | 'cousinFull' | 'cousinPaternal'
  | 'husband' | 'freedSlaveMale'
  | 'daughter' | 'granddaughter' | 'mother'
  | 'paternalGrandmother' | 'maternalGrandmother'
  | 'fullSister' | 'paternalSister' | 'maternalSister'
  | 'wife' | 'freedSlaveFemale';

export interface HeirDefinition {
  id: HeirKey;
  nameEn: string;
  nameAr: string;
  gender: 'M' | 'F';
}

export interface CalculationResult {
  heirId: HeirKey;
  heirName: string;
  count: number;
  shareFraction: string;
  sharePercentage: number;
  shareAmount: number;
  isBlocked: boolean;
  blockedBy?: string;
  explanation: string;
  quranReference?: string;
}

export interface InheritanceState {
  totalEstate: number;
  currency: string;
  deceasedGender: DeceasedGender;
  school: FiqhSchool;
  language: string;
  heirs: Record<HeirKey, number>;
}

import { HeirKey, CalculationResult, DeceasedGender, InheritanceState, FiqhSchool } from '../types';
import { ALL_HEIRS } from '../constants';

/**
 * Simplified logic for Al-Farai'd. 
 * This is a highly complex area. This implementation handles primary shares (Furud),
 * Blocking (Hajb), Residue (Asaba), and basic Awl/Radd.
 */

export const calculateInheritance = (state: InheritanceState): CalculationResult[] => {
  const { totalEstate, deceasedGender, heirs } = state;
  let results: CalculationResult[] = [];

  // 1. Initial Filtering & Blocking
  // A person cannot be their own heir. 
  // If male, no husband. If female, no wife.
  const activeHeirs = { ...heirs };
  if (deceasedGender === DeceasedGender.Male) activeHeirs.husband = 0;
  if (deceasedGender === DeceasedGender.Female) activeHeirs.wife = 0;

  const hasChildren = (activeHeirs.son || 0) > 0 || (activeHeirs.daughter || 0) > 0 || (activeHeirs.grandson || 0) > 0 || (activeHeirs.granddaughter || 0) > 0;
  const hasSons = (activeHeirs.son || 0) > 0 || (activeHeirs.grandson || 0) > 0;
  const hasMultipleSiblings = (
    (activeHeirs.fullBrother || 0) + (activeHeirs.fullSister || 0) + 
    (activeHeirs.paternalBrother || 0) + (activeHeirs.paternalSister || 0) + 
    (activeHeirs.maternalBrother || 0) + (activeHeirs.maternalSister || 0)
  ) > 1;

  // Primary Shares Tracker
  let fixedSharesTotal = 0;
  const shares: Partial<Record<HeirKey, number>> = {};
  const blocked: Partial<Record<HeirKey, string>> = {};

  // --- HAJB (BLOCKING) RULES ---
  if (activeHeirs.father > 0) blocked.grandfather = 'Father';
  if (hasSons) {
    blocked.fullBrother = 'Son/Grandson';
    blocked.paternalBrother = 'Son/Grandson';
    blocked.maternalBrother = 'Son/Grandson';
    blocked.maternalSister = 'Son/Grandson';
    blocked.nephewFull = 'Son/Grandson';
    blocked.nephewPaternal = 'Son/Grandson';
    blocked.uncleFull = 'Son/Grandson';
    blocked.unclePaternal = 'Son/Grandson';
  }
  if (activeHeirs.father > 0) {
    blocked.fullBrother = 'Father';
    blocked.paternalBrother = 'Father';
    blocked.maternalBrother = 'Father';
    blocked.maternalSister = 'Father';
    blocked.nephewFull = 'Father';
    blocked.nephewPaternal = 'Father';
  }
  if (activeHeirs.son > 0) blocked.grandson = 'Son';
  if (activeHeirs.mother > 0) {
    blocked.paternalGrandmother = 'Mother';
    blocked.maternalGrandmother = 'Mother';
  }

  // --- CALCULATE FIXED SHARES (ASHAB UL FURUD) ---

  // Husband / Wife
  if (activeHeirs.husband > 0 && !blocked.husband) {
    shares.husband = hasChildren ? 1/4 : 1/2;
    fixedSharesTotal += shares.husband;
  }
  if (activeHeirs.wife > 0 && !blocked.wife) {
    shares.wife = hasChildren ? 1/8 : 1/4;
    fixedSharesTotal += shares.wife;
  }

  // Father / Mother
  if (activeHeirs.father > 0 && !blocked.father) {
    if (hasChildren) {
      shares.father = 1/6;
      fixedSharesTotal += 1/6;
    }
  }
  if (activeHeirs.mother > 0 && !blocked.mother) {
    if (hasChildren || hasMultipleSiblings) {
      shares.mother = 1/6;
    } else {
      shares.mother = 1/3;
    }
    fixedSharesTotal += shares.mother;
  }

  // Daughters
  if (activeHeirs.daughter > 0 && !activeHeirs.son) {
    shares.daughter = activeHeirs.daughter === 1 ? 1/2 : 2/3;
    fixedSharesTotal += shares.daughter;
  }

  // Siblings
  if (!hasSons && !activeHeirs.father) {
    if (activeHeirs.fullSister > 0 && !activeHeirs.fullBrother) {
       shares.fullSister = activeHeirs.fullSister === 1 ? 1/2 : 2/3;
       fixedSharesTotal += shares.fullSister;
    }
    // Maternal Siblings
    const matSibCount = (activeHeirs.maternalBrother || 0) + (activeHeirs.maternalSister || 0);
    if (matSibCount > 0) {
      const share = matSibCount === 1 ? 1/6 : 1/3;
      if (activeHeirs.maternalBrother > 0) shares.maternalBrother = share * (activeHeirs.maternalBrother / matSibCount);
      if (activeHeirs.maternalSister > 0) shares.maternalSister = share * (activeHeirs.maternalSister / matSibCount);
      fixedSharesTotal += share;
    }
  }

  // --- CALCULATE RESIDUE (ASABAT) ---
  let residue = 1 - fixedSharesTotal;
  const asabaList: HeirKey[] = [];

  // Hierarchy of Asaba
  if (activeHeirs.son > 0 || activeHeirs.daughter > 0) {
    if (activeHeirs.son > 0) {
      asabaList.push('son');
      if (activeHeirs.daughter > 0) asabaList.push('daughter');
    }
  } else if (activeHeirs.father > 0 && !hasChildren) {
    asabaList.push('father');
  } else if (activeHeirs.fullBrother > 0 || activeHeirs.fullSister > 0) {
    if (activeHeirs.fullBrother > 0) {
      asabaList.push('fullBrother');
      if (activeHeirs.fullSister > 0) asabaList.push('fullSister');
    }
  }

  if (residue > 0 && asabaList.length > 0) {
    let totalWeight = 0;
    asabaList.forEach(k => {
      const def = ALL_HEIRS.find(h => h.id === k);
      const count = activeHeirs[k];
      const weight = def?.gender === 'M' ? 2 : 1;
      totalWeight += weight * count;
    });

    asabaList.forEach(k => {
      const def = ALL_HEIRS.find(h => h.id === k);
      const count = activeHeirs[k];
      const weight = def?.gender === 'M' ? 2 : 1;
      const individualShare = (residue * weight) / totalWeight;
      shares[k] = (shares[k] || 0) + individualShare * count;
    });
    residue = 0;
  }

  // --- AWL & RADD (ADJUSTMENTS) ---
  // If shares total > 1 (Awl)
  const totalRawShare = Object.values(shares).reduce((a, b) => a + b, 0);
  if (totalRawShare > 1) {
    Object.keys(shares).forEach(k => {
      shares[k as HeirKey]! /= totalRawShare;
    });
  } 
  // If shares total < 1 and no asaba (Radd)
  else if (totalRawShare < 1 && totalRawShare > 0) {
    // Basic Radd: Spouse doesn't get Radd.
    const spouseShare = (shares.husband || 0) + (shares.wife || 0);
    const othersShareTotal = totalRawShare - spouseShare;
    if (othersShareTotal > 0) {
        const remaining = 1 - spouseShare;
        Object.keys(shares).forEach(k => {
          if (k !== 'husband' && k !== 'wife') {
            shares[k as HeirKey]! = (shares[k as HeirKey]! / othersShareTotal) * remaining;
          }
        });
    }
  }

  // Map to results
  ALL_HEIRS.forEach(def => {
    const count = activeHeirs[def.id];
    if (count > 0 || blocked[def.id]) {
      const share = shares[def.id] || 0;
      results.push({
        heirId: def.id,
        heirName: `${def.nameEn} (${def.nameAr})`,
        count,
        shareFraction: formatFraction(share),
        sharePercentage: share * 100,
        shareAmount: share * totalEstate,
        isBlocked: !!blocked[def.id],
        blockedBy: blocked[def.id],
        explanation: getExplanation(def.id, !!blocked[def.id], blocked[def.id]),
        quranReference: getQuranRef(def.id)
      });
    }
  });

  return results;
};

const formatFraction = (val: number): string => {
  if (val === 0) return '0';
  if (Math.abs(val - 1/2) < 0.001) return '1/2';
  if (Math.abs(val - 1/3) < 0.001) return '1/3';
  if (Math.abs(val - 1/4) < 0.001) return '1/4';
  if (Math.abs(val - 1/6) < 0.001) return '1/6';
  if (Math.abs(val - 1/8) < 0.001) return '1/8';
  if (Math.abs(val - 2/3) < 0.001) return '2/3';
  return val.toFixed(4);
};

const getExplanation = (id: HeirKey, isBlocked: boolean, blockedBy?: string): string => {
  if (isBlocked) return `Blocked (Hajb) due to the presence of ${blockedBy}.`;
  return `Receives a share based on the Quranic rules of Al-Farai'd.`;
};

const getQuranRef = (id: HeirKey): string => {
  if (id === 'son' || id === 'daughter') return '4:11';
  if (id === 'husband' || id === 'wife') return '4:12';
  if (id === 'father' || id === 'mother') return '4:11';
  if (id.includes('Brother') || id.includes('Sister')) return '4:12 or 4:176';
  return 'General Sunnah / Ijma';
};

import React, { useState, useMemo, useEffect } from 'react';
import { 
  InheritanceState, 
  DeceasedGender, 
  FiqhSchool, 
  HeirKey, 
  CalculationResult 
} from './types';
import { 
  CURRENCIES, 
  LANGUAGES, 
  MALE_HEIRS, 
  FEMALE_HEIRS, 
  i18nStrings 
} from './constants';
import { calculateInheritance } from './logic/calculator';
import { 
  PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend 
} from 'recharts';
import { 
  Calculator, User, Users, Globe, Landmark, 
  ArrowRight, RotateCcw, Download, Printer, Moon, Sun, 
  CheckCircle2, Info, AlertCircle
} from 'lucide-react';

const COLORS = ['#10b981', '#3b82f6', '#8b5cf6', '#f59e0b', '#ef4444', '#ec4899', '#06b6d4', '#84cc16'];

const App: React.FC = () => {
  // --- State ---
  const [state, setState] = useState<InheritanceState>({
    totalEstate: 100000,
    currency: 'USD',
    deceasedGender: DeceasedGender.Male,
    school: FiqhSchool.Hanafi,
    language: 'en',
    heirs: {} as Record<HeirKey, number>
  });

  const [darkMode, setDarkMode] = useState(false);
  const [isCalculated, setIsCalculated] = useState(false);

  const t = i18nStrings[state.language] || i18nStrings.en;

  // --- Logic ---
  const results = useMemo(() => {
    return calculateInheritance(state);
  }, [state]);

  const chartData = useMemo(() => {
    return results
      .filter(r => r.shareAmount > 0)
      .map(r => ({ name: r.heirName, value: r.shareAmount }));
  }, [results]);

  // --- Handlers ---
  const handleHeirChange = (key: HeirKey, value: number) => {
    setState(prev => ({
      ...prev,
      heirs: { ...prev.heirs, [key]: value }
    }));
  };

  const resetAll = () => {
    setState({
      totalEstate: 100000,
      currency: 'USD',
      deceasedGender: DeceasedGender.Male,
      school: FiqhSchool.Hanafi,
      language: 'en',
      heirs: {} as Record<HeirKey, number>
    });
    setIsCalculated(false);
  };

  const toggleDarkMode = () => setDarkMode(!darkMode);

  const handlePrint = () => window.print();

  // Effects
  useEffect(() => {
    if (darkMode) {
      document.body.classList.add('bg-slate-900', 'text-slate-100');
      document.body.classList.remove('bg-slate-50', 'text-slate-900');
    } else {
      document.body.classList.remove('bg-slate-900', 'text-slate-100');
      document.body.classList.add('bg-slate-50', 'text-slate-900');
    }
  }, [darkMode]);

  return (
    <div className={`min-h-screen pb-20 px-4 md:px-8 transition-colors duration-300 ${darkMode ? 'dark text-white' : ''}`}>
      {/* Header */}
      <header className="max-w-6xl mx-auto py-8 flex flex-col md:flex-row justify-between items-center gap-4">
        <div className="flex items-center gap-3">
          <div className="bg-emerald-600 p-2 rounded-xl shadow-lg shadow-emerald-200">
            <Landmark className="text-white w-8 h-8" />
          </div>
          <div>
            <h1 className="text-2xl font-bold tracking-tight font-arabic">{t.title}</h1>
            <p className="text-slate-500 text-sm font-medium">{t.subtitle}</p>
          </div>
        </div>

        <div className="flex items-center gap-2">
          <button onClick={toggleDarkMode} className="p-2 hover:bg-slate-200 dark:hover:bg-slate-800 rounded-full transition-colors">
            {darkMode ? <Sun size={20} /> : <Moon size={20} />}
          </button>
          <div className="flex items-center gap-2 bg-white dark:bg-slate-800 p-1 rounded-full shadow-sm border border-slate-200 dark:border-slate-700">
            <Globe size={18} className="ml-2 text-slate-400" />
            <select 
              value={state.language} 
              onChange={(e) => setState({...state, language: e.target.value})}
              className="bg-transparent border-none text-sm font-medium focus:ring-0 pr-8"
            >
              {LANGUAGES.map(l => <option key={l.code} value={l.code}>{l.name}</option>)}
            </select>
          </div>
        </div>
      </header>

      <main className="max-w-6xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Input Panel */}
        <div className="lg:col-span-5 space-y-6 no-print">
          <section className="bg-white dark:bg-slate-800 p-6 rounded-3xl shadow-sm border border-slate-200 dark:border-slate-700">
            <h2 className="text-lg font-bold mb-4 flex items-center gap-2">
              <Calculator className="text-emerald-500" size={20} />
              {t.summary}
            </h2>

            <div className="space-y-4">
              <div>
                <label className="block text-xs font-semibold uppercase text-slate-400 mb-1">{t.estateValue}</label>
                <div className="relative">
                  <input 
                    type="number" 
                    value={state.totalEstate} 
                    onChange={(e) => setState({...state, totalEstate: Number(e.target.value)})}
                    className="w-full bg-slate-50 dark:bg-slate-900 border-none rounded-xl py-3 px-4 font-bold text-lg focus:ring-2 focus:ring-emerald-500"
                  />
                  <select 
                    value={state.currency} 
                    onChange={(e) => setState({...state, currency: e.target.value})}
                    className="absolute right-2 top-2 bottom-2 bg-emerald-50 dark:bg-emerald-900/30 text-emerald-600 dark:text-emerald-400 text-xs font-bold rounded-lg border-none focus:ring-0"
                  >
                    {CURRENCIES.map(c => <option key={c} value={c}>{c}</option>)}
                  </select>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-semibold uppercase text-slate-400 mb-1">{t.deceasedGender}</label>
                  <div className="flex p-1 bg-slate-100 dark:bg-slate-900 rounded-xl">
                    <button 
                      onClick={() => setState({...state, deceasedGender: DeceasedGender.Male})}
                      className={`flex-1 py-2 text-sm font-bold rounded-lg transition-all ${state.deceasedGender === DeceasedGender.Male ? 'bg-white dark:bg-slate-800 shadow-sm text-emerald-600' : 'text-slate-400'}`}
                    >
                      {t.male}
                    </button>
                    <button 
                      onClick={() => setState({...state, deceasedGender: DeceasedGender.Female})}
                      className={`flex-1 py-2 text-sm font-bold rounded-lg transition-all ${state.deceasedGender === DeceasedGender.Female ? 'bg-white dark:bg-slate-800 shadow-sm text-pink-600' : 'text-slate-400'}`}
                    >
                      {t.female}
                    </button>
                  </div>
                </div>
                <div>
                  <label className="block text-xs font-semibold uppercase text-slate-400 mb-1">{t.fiqhSchool}</label>
                  <select 
                    value={state.school} 
                    onChange={(e) => setState({...state, school: e.target.value as FiqhSchool})}
                    className="w-full bg-slate-50 dark:bg-slate-900 border-none rounded-xl py-3 px-4 font-bold text-sm focus:ring-2 focus:ring-emerald-500"
                  >
                    {Object.values(FiqhSchool).map(s => <option key={s} value={s}>{s}</option>)}
                  </select>
                </div>
              </div>
            </div>
          </section>

          <section className="bg-white dark:bg-slate-800 p-6 rounded-3xl shadow-sm border border-slate-200 dark:border-slate-700">
            <h2 className="text-lg font-bold mb-4 flex items-center gap-2">
              <Users className="text-emerald-500" size={20} />
              {t.heirsSelection}
            </h2>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {(state.deceasedGender === DeceasedGender.Male ? FEMALE_HEIRS : MALE_HEIRS).map(h => {
                if (h.id === 'husband' || h.id === 'wife') {
                  return (
                    <div key={h.id} className="bg-slate-50 dark:bg-slate-900 p-3 rounded-2xl">
                      <label className="block text-xs font-bold text-slate-500 mb-2 font-arabic">{h.nameEn} ({h.nameAr})</label>
                      <input 
                        type="number" min="0" max={h.id === 'wife' ? 4 : 1}
                        value={state.heirs[h.id] || 0}
                        onChange={(e) => handleHeirChange(h.id, Number(e.target.value))}
                        className="w-full bg-white dark:bg-slate-800 border-none rounded-lg text-sm font-bold"
                      />
                    </div>
                  );
                }
                return null;
              })}

              {MALE_HEIRS.filter(h => h.id !== 'husband' && h.id !== 'freedSlaveMale').map(h => (
                <div key={h.id} className="bg-slate-50 dark:bg-slate-900 p-3 rounded-2xl">
                  <label className="block text-xs font-bold text-slate-500 mb-2 font-arabic">{h.nameEn} ({h.nameAr})</label>
                  <input 
                    type="number" min="0" max="10"
                    value={state.heirs[h.id] || 0}
                    onChange={(e) => handleHeirChange(h.id, Number(e.target.value))}
                    className="w-full bg-white dark:bg-slate-800 border-none rounded-lg text-sm font-bold"
                  />
                </div>
              ))}

              {FEMALE_HEIRS.filter(h => h.id !== 'wife' && h.id !== 'freedSlaveFemale').map(h => (
                <div key={h.id} className="bg-slate-50 dark:bg-slate-900 p-3 rounded-2xl">
                  <label className="block text-xs font-bold text-slate-500 mb-2 font-arabic">{h.nameEn} ({h.nameAr})</label>
                  <input 
                    type="number" min="0" max="10"
                    value={state.heirs[h.id] || 0}
                    onChange={(e) => handleHeirChange(h.id, Number(e.target.value))}
                    className="w-full bg-white dark:bg-slate-800 border-none rounded-lg text-sm font-bold"
                  />
                </div>
              ))}
            </div>

            <div className="mt-8 flex gap-3">
              <button 
                onClick={() => setIsCalculated(true)}
                className="flex-1 bg-emerald-600 hover:bg-emerald-700 text-white font-bold py-4 px-6 rounded-2xl shadow-lg shadow-emerald-200 dark:shadow-none transition-all flex items-center justify-center gap-2"
              >
                {t.calculate}
                <ArrowRight size={20} />
              </button>
              <button 
                onClick={resetAll}
                className="bg-slate-100 dark:bg-slate-700 hover:bg-slate-200 dark:hover:bg-slate-600 p-4 rounded-2xl transition-all"
              >
                <RotateCcw size={20} />
              </button>
            </div>
          </section>
        </div>

        {/* Results Panel */}
        <div className="lg:col-span-7 space-y-6">
          {!isCalculated ? (
            <div className="bg-emerald-50 dark:bg-emerald-900/20 border-2 border-dashed border-emerald-200 dark:border-emerald-800 rounded-3xl p-12 flex flex-col items-center text-center">
              <div className="bg-white dark:bg-slate-800 p-4 rounded-full shadow-md mb-6">
                <Info size={40} className="text-emerald-500" />
              </div>
              <h3 className="text-xl font-bold text-emerald-900 dark:text-emerald-100 mb-2">{t.results}</h3>
              <p className="text-emerald-700 dark:text-emerald-400 max-w-sm">{t.noHeirs}</p>
            </div>
          ) : (
            <>
              {/* Chart & Stats */}
              <div className="bg-white dark:bg-slate-800 p-6 rounded-3xl shadow-sm border border-slate-200 dark:border-slate-700">
                <div className="flex justify-between items-center mb-6">
                  <h2 className="text-lg font-bold">{t.results}</h2>
                  <div className="flex gap-2 no-print">
                    <button onClick={handlePrint} className="p-2 bg-slate-50 dark:bg-slate-900 hover:bg-slate-100 rounded-xl transition-all">
                      <Printer size={18} />
                    </button>
                    <button className="p-2 bg-slate-50 dark:bg-slate-900 hover:bg-slate-100 rounded-xl transition-all">
                      <Download size={18} />
                    </button>
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-8 items-center">
                  <div className="h-64">
                    <ResponsiveContainer width="100%" height="100%">
                      <PieChart>
                        <Pie
                          data={chartData}
                          innerRadius={60}
                          outerRadius={80}
                          paddingAngle={5}
                          dataKey="value"
                        >
                          {chartData.map((entry, index) => (
                            <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                          ))}
                        </Pie>
                        <Tooltip />
                        <Legend verticalAlign="bottom" height={36}/>
                      </PieChart>
                    </ResponsiveContainer>
                  </div>
                  <div className="space-y-4">
                    <div className="bg-emerald-50 dark:bg-emerald-900/30 p-4 rounded-2xl">
                      <p className="text-xs font-bold text-emerald-600 dark:text-emerald-400 uppercase">{t.estateValue}</p>
                      <p className="text-2xl font-black text-emerald-700 dark:text-emerald-300">
                        {state.totalEstate.toLocaleString()} <span className="text-sm font-bold">{state.currency}</span>
                      </p>
                    </div>
                    <div className="flex gap-4">
