import React from 'react';
import { HeirKey, CalculationResult, DeceasedGender } from './types';

interface FamilyTreeProps {
  results: CalculationResult[];
  deceasedGender: DeceasedGender;
  currency: string;
}

interface NodePos {
  x: number;
  y: number;
  id: HeirKey | 'deceased';
  label: string;
}

export const FamilyTree: React.FC<FamilyTreeProps> = ({ results, deceasedGender, currency }) => {
  const nodeWidth = 140;
  const nodeHeight = 70;

  // Define static positions for a clean hierarchical tree
  const positions: Record<string, { x: number; y: number }> = {
    deceased: { x: 400, y: 250 },
    // Ascendants
    father: { x: 300, y: 120 },
    mother: { x: 500, y: 120 },
    grandfather: { x: 200, y: 40 },
    paternalGrandmother: { x: 350, y: 40 },
    maternalGrandmother: { x: 550, y: 40 },
    // Spouses
    husband: { x: 650, y: 250 },
    wife: { x: 650, y: 250 },
    // Descendants
    son: { x: 300, y: 400 },
    daughter: { x: 500, y: 400 },
    grandson: { x: 300, y: 520 },
    granddaughter: { x: 500, y: 520 },
    // Siblings (Lateral)
    fullBrother: { x: 100, y: 200 },
    fullSister: { x: 100, y: 300 },
    paternalBrother: { x: 50, y: 150 },
    paternalSister: { x: 50, y: 350 },
    maternalBrother: { x: 150, y: 150 },
    maternalSister: { x: 150, y: 350 },
  };

  const activeResults = results.filter(r => r.count > 0 || r.isBlocked);

  const renderNode = (id: HeirKey | 'deceased', label: string, share?: string, isBlocked?: boolean) => {
    const pos = positions[id];
    if (!pos) return null;

    const x = pos.x - nodeWidth / 2;
    const y = pos.y - nodeHeight / 2;

    const isDeceased = id === 'deceased';
    const bgColor = isDeceased ? '#475569' : isBlocked ? '#fecaca' : '#ecfdf5';
    const borderColor = isDeceased ? '#1e293b' : isBlocked ? '#ef4444' : '#10b981';
    const textColor = isDeceased ? '#ffffff' : isBlocked ? '#991b1b' : '#065f46';

    return (
      <g key={id} className="transition-all duration-500 ease-in-out">
        <rect
          x={x}
          y={y}
          width={nodeWidth}
          height={nodeHeight}
          rx="12"
          fill={bgColor}
          stroke={borderColor}
          strokeWidth="2"
          className="drop-shadow-sm"
        />
        <text
          x={pos.x}
          y={pos.y - (share ? 8 : 0)}
          textAnchor="middle"
          dominantBaseline="middle"
          fill={textColor}
          className="text-[11px] font-bold font-arabic"
        >
          {label}
        </text>
        {share && !isBlocked && (
          <text
            x={pos.x}
            y={pos.y + 14}
            textAnchor="middle"
            dominantBaseline="middle"
            fill={textColor}
            className="text-[14px] font-black"
          >
            {share}
          </text>
        )}
        {isBlocked && (
          <text
            x={pos.x}
            y={pos.y + 14}
            textAnchor="middle"
            dominantBaseline="middle"
            fill="#ef4444"
            className="text-[9px] font-black uppercase"
          >
            Blocked
          </text>
        )}
      </g>
    );
  };

  const renderConnection = (fromId: string, toId: string) => {
    const from = positions[fromId];
    const to = positions[toId];
    if (!from || !to) return null;

    return (
      <line
        key={`${fromId}-${toId}`}
        x1={from.x}
        y1={from.y}
        x2={to.x}
        y2={to.y}
        stroke="#cbd5e1"
        strokeWidth="1.5"
        strokeDasharray="4 2"
      />
    );
  };

  return (
    <div className="w-full overflow-hidden bg-slate-50 dark:bg-slate-900/50 rounded-3xl border border-slate-200 dark:border-slate-800 p-4">
      <svg viewBox="0 0 800 600" className="w-full h-auto max-h-[500px]">
        {/* Connection Lines */}
        {activeResults.map(r => renderConnection('deceased', r.heirId))}

        {/* Core Deceased Node */}
        {renderNode('deceased', `Deceased (${deceasedGender})`)}

        {/* Heir Nodes */}
        {activeResults.map(r => 
          renderNode(r.heirId, r.heirName, `${r.sharePercentage.toFixed(1)}%`, r.isBlocked)
        )}
      </svg>
    </div>
  );
};

