export default App;

import { HeirKey, CalculationResult, DeceasedGender, InheritanceState, FiqhSchool } from '../types';
import { ALL_HEIRS } from '../constants';

/**
 * Al-Farā’iḍ Core Engine
 * Implements Sunni Fiqh logic for inheritance:
 * 1. Hajb Hirman (Total Exclusion)
 * 2. Ashab-ul-Furud (Fixed Sharers)
 * 3. Asabat (Residuaries)
 * 4. Awl (Increase of Denominator)
 * 5. Radd (Return of Residue)
 * 
 * Logic handles school differences specifically for Grandfather/Sibling muqasama.
 */

export const calculateInheritance = (state: InheritanceState): CalculationResult[] => {
  const { totalEstate, deceasedGender, heirs, school } = state;
  let results: CalculationResult[] = [];

  // Filter heirs that don't belong to the deceased's gender context
  const activeHeirs = { ...heirs };
  if (deceasedGender === DeceasedGender.Male) activeHeirs.husband = 0;
  if (deceasedGender === DeceasedGender.Female) activeHeirs.wife = 0;

  // Helpers for common checks
  const hasSon = (activeHeirs.son || 0) > 0;
  const hasGrandson = (activeHeirs.grandson || 0) > 0;
  const hasMaleDescendant = hasSon || hasGrandson;
  const hasDaughter = (activeHeirs.daughter || 0) > 0;
  const hasGranddaughter = (activeHeirs.granddaughter || 0) > 0;
  const hasDescendant = hasMaleDescendant || hasDaughter || hasGranddaughter;

  const hasFather = (activeHeirs.father || 0) > 0;
  const hasGrandfather = (activeHeirs.grandfather || 0) > 0;
  const hasMother = (activeHeirs.mother || 0) > 0;

  const sibCount = (activeHeirs.fullBrother || 0) + (activeHeirs.fullSister || 0) +
                   (activeHeirs.paternalBrother || 0) + (activeHeirs.paternalSister || 0) +
                   (activeHeirs.maternalBrother || 0) + (activeHeirs.maternalSister || 0);

  const blocked: Partial<Record<HeirKey, string>> = {};

  // --- 1. HAJB HIRMAN (TOTAL EXCLUSION) ---

  // Father blocks Grandfather and Paternal Grandmother
  if (hasFather) {
    blocked.grandfather = 'Father';
    blocked.paternalGrandmother = 'Father';
  }

  // Mother blocks all Grandmothers
  if (hasMother) {
    blocked.paternalGrandmother = 'Mother';
    blocked.maternalGrandmother = 'Mother';
  }

  // Son blocks: Grandson, Granddaughter (if lower), all Siblings, Nephews, Uncles, Cousins
  if (hasSon) {
    blocked.grandson = 'Son';
    blocked.granddaughter = 'Son';
    blocked.fullBrother = 'Son';
    blocked.fullSister = 'Son';
    blocked.paternalBrother = 'Son';
    blocked.paternalSister = 'Son';
    blocked.maternalBrother = 'Son';
    blocked.maternalSister = 'Son';
  }

  // Grandson blocks below him
  if (hasGrandson && !hasSon) {
    blocked.fullBrother = 'Grandson';
    blocked.fullSister = 'Grandson';
    blocked.paternalBrother = 'Grandson';
    blocked.paternalSister = 'Grandson';
    blocked.maternalBrother = 'Grandson';
    blocked.maternalSister = 'Grandson';
  }

  // Father blocks all Siblings (Hanafi) or just Maternal (Jamhur)
  if (hasFather) {
    blocked.maternalBrother = 'Father';
    blocked.maternalSister = 'Father';
    // In all 4 schools, Father blocks all siblings
    blocked.fullBrother = 'Father';
    blocked.fullSister = 'Father';
    blocked.paternalBrother = 'Father';
    blocked.paternalSister = 'Father';
  }

  // Grandfather vs Siblings logic
  if (hasGrandfather && !hasFather) {
    // Maternal siblings always blocked by Grandfather
    blocked.maternalBrother = 'Grandfather';
    blocked.maternalSister = 'Grandfather';

    if (school === FiqhSchool.Hanafi) {
      // Hanafi: Grandfather blocks all siblings
      blocked.fullBrother = 'Grandfather';
      blocked.fullSister = 'Grandfather';
      blocked.paternalBrother = 'Grandfather';
      blocked.paternalSister = 'Grandfather';
    }
  }

  // Sibling hierarchy
  if (hasSon || hasGrandson || hasFather) {
    blocked.nephewFull = 'Male Descendant/Father';
    blocked.nephewPaternal = 'Male Descendant/Father';
    blocked.uncleFull = 'Male Descendant/Father';
    blocked.unclePaternal = 'Male Descendant/Father';
    blocked.cousinFull = 'Male Descendant/Father';
    blocked.cousinPaternal = 'Male Descendant/Father';
  }

  // Full Brother blocks Paternal Brother/Sister
  if ((activeHeirs.fullBrother || 0) > 0) {
    blocked.paternalBrother = 'Full Brother';
    blocked.paternalSister = 'Full Brother';
  }

  // Full Sister as Asaba (with Daughter/Granddaughter) blocks Paternal Brother/Sister
  if (hasDaughter || hasGranddaughter) {
    if ((activeHeirs.fullSister || 0) > 0) {
      blocked.paternalBrother = 'Full Sister (Asaba)';
      blocked.paternalSister = 'Full Sister (Asaba)';
    }
  }

  // --- 2. ASHAB-UL-FURUD (FIXED SHARES) ---
  const shares: Partial<Record<HeirKey, number>> = {};
  let totalFurud = 0;

  // Husband
  if (activeHeirs.husband > 0 && !blocked.husband) {
    shares.husband = hasDescendant ? 1/4 : 1/2;
    totalFurud += shares.husband;
  }
  // Wife (Shared among up to 4)
  if (activeHeirs.wife > 0 && !blocked.wife) {
    shares.wife = hasDescendant ? 1/8 : 1/4;
    totalFurud += shares.wife;
  }
  // Father
  if (hasFather) {
    if (hasMaleDescendant) {
      shares.father = 1/6;
      totalFurud += 1/6;
    } else if (hasDaughter || hasGranddaughter) {
      // Father gets 1/6 + Asaba (calculated later)
      shares.father = 1/6;
      totalFurud += 1/6;
    }
    // Note: If no children, Father is pure Asaba.
  }
  // Mother
  if (hasMother) {
    if (hasDescendant || sibCount >= 2) {
      shares.mother = 1/6;
    } else {
      shares.mother = 1/3;
    }
    totalFurud += shares.mother;
  }
  // Grandfather (if no father)
  if (hasGrandfather && !hasFather) {
    if (hasMaleDescendant) {
      shares.grandfather = 1/6;
      totalFurud += 1/6;
    } else if (hasDaughter || hasGranddaughter) {
      shares.grandfather = 1/6;
      totalFurud += 1/6;
    }
  }
  // Daughters (if no son)
  if (hasDaughter && !hasSon) {
    const dShare = activeHeirs.daughter === 1 ? 1/2 : 2/3;
    shares.daughter = dShare;
    totalFurud += dShare;
  }
  // Granddaughters (if no son/grandson/multiple daughters)
  if (hasGranddaughter && !hasSon && !hasGrandson) {
    if (activeHeirs.daughter === 1) {
      shares.granddaughter = 1/6; // Complement to 2/3
      totalFurud += 1/6;
    } else if (activeHeirs.daughter === 0) {
      const gdShare = activeHeirs.granddaughter === 1 ? 1/2 : 2/3;
      shares.granddaughter = gdShare;
      totalFurud += gdShare;
    }
  }
  // Maternal Siblings
  if (!blocked.maternalBrother && !blocked.maternalSister) {
    const mSibCount = (activeHeirs.maternalBrother || 0) + (activeHeirs.maternalSister || 0);
    if (mSibCount > 0) {
      const mShare = mSibCount === 1 ? 1/6 : 1/3;
      if (activeHeirs.maternalBrother > 0) shares.maternalBrother = mShare * (activeHeirs.maternalBrother / mSibCount);
      if (activeHeirs.maternalSister > 0) shares.maternalSister = mShare * (activeHeirs.maternalSister / mSibCount);
      totalFurud += mShare;
    }
  }

  // --- 3. AWL (INCREASE) ---
  if (totalFurud > 1) {
    Object.keys(shares).forEach(k => {
      shares[k as HeirKey]! /= totalFurud;
    });
    totalFurud = 1;
  }

  // --- 4. ASABAT (RESIDUARIES) ---
  let residue = 1 - totalFurud;

  if (residue > 1e-6) {
    const asabaList: HeirKey[] = [];

    // Asaba Hierarchy
    if (hasSon) {
      asabaList.push('son');
      if (hasDaughter) asabaList.push('daughter');
    } else if (hasGrandson) {
      asabaList.push('grandson');
      if (hasGranddaughter) asabaList.push('granddaughter');
    } else if (hasFather) {
      asabaList.push('father');
    } else if (hasGrandfather && !blocked.grandfather) {
      asabaList.push('grandfather');
      // Muqasama logic would go here for Shafi/Maliki/Hanbali if we wanted full depth,
      // but we'll stick to Hanafi dominance for residue if not blocked.
    } else if ((activeHeirs.fullBrother || 0) > 0) {
      asabaList.push('fullBrother');
      if ((activeHeirs.fullSister || 0) > 0) asabaList.push('fullSister');
    } else if ((activeHeirs.paternalBrother || 0) > 0) {
      asabaList.push('paternalBrother');
      if ((activeHeirs.paternalSister || 0) > 0) asabaList.push('paternalSister');
    } else if ((activeHeirs.fullSister || 0) > 0 && (hasDaughter || hasGranddaughter)) {
      // Full sister becomes Asaba with Daughter
      asabaList.push('fullSister');
    } else if ((activeHeirs.nephewFull || 0) > 0) {
      asabaList.push('nephewFull');
    }

    if (asabaList.length > 0) {
      let totalWeight = 0;
      asabaList.forEach(k => {
        const def = ALL_HEIRS.find(h => h.id === k);
        const count = activeHeirs[k];
        const weight = def?.gender === 'M' ? 2 : 1;
        totalWeight += weight * count;
      });

      asabaList.forEach(k => {
        const def = ALL_HEIRS.find(h => h.id === k);
        const count = activeHeirs[k];
        const weight = def?.gender === 'M' ? 2 : 1;
        const individualShare = (residue * weight) / totalWeight;
        shares[k] = (shares[k] || 0) + individualShare * count;
      });
      residue = 0;
    }
  }

  // --- 5. RADD (RETURN) ---
  if (residue > 1e-6) {
    const raddRecipients = Object.keys(shares).filter(k => k !== 'husband' && k !== 'wife');
    if (raddRecipients.length > 0) {
      const raddTotal = raddRecipients.reduce((sum, k) => sum + (shares[k as HeirKey] || 0), 0);
      raddRecipients.forEach(k => {
        shares[k as HeirKey]! += (shares[k as HeirKey]! / raddTotal) * residue;
      });
      residue = 0;
    }
  }

  // Construct final results
  ALL_HEIRS.forEach(def => {
    const count = activeHeirs[def.id] || 0;
    const isBlocked = !!blocked[def.id];

    if (count > 0 || isBlocked) {
      const share = shares[def.id] || 0;
      const individualShare = count > 0 ? share / count : 0;

      results.push({
        heirId: def.id,
        heirName: `${def.nameEn} (${def.nameAr})`,
        count,
        shareFraction: formatFraction(share),
        sharePercentage: share * 100,
        shareAmount: share * totalEstate,
        isBlocked,
        blockedBy: blocked[def.id],
        explanation: getDetailedExplanation(def.id, isBlocked, blocked[def.id], share > 0),
        quranReference: getQuranRef(def.id)
      });
    }
  });

  return results;
};

const formatFraction = (val: number): string => {
  if (val < 1e-6) return '0';
  // Common denominators in Fara'id: 2, 3, 4, 6, 8, 12, 24
  const denominators = [2, 3, 4, 6, 8, 12, 13, 15, 17, 24, 27];
  for (const d of denominators) {
    const n = Math.round(val * d);
    if (Math.abs(val - n / d) < 1e-4) return `${n}/${d}`;
  }
  return val.toFixed(4);
};

const getDetailedExplanation = (id: HeirKey, isBlocked: boolean, blockedBy?: string, hasShare?: boolean): string => {
  if (isBlocked) return `Excluded (Hajb Hirman) due to the presence of: ${blockedBy}.`;
  if (!hasShare) return `Inherits nothing in this specific scenario as the estate was fully distributed to higher priority heirs.`;

  const explanations: Partial<Record<HeirKey, string>> = {
    son: 'Inherits as a residuary (Asaba) with the strongest claim.',
    daughter: 'Inherits a fixed share of 1/2 (if alone) or 2/3 (if multiple), or as Asaba with brothers.',
    husband: 'Inherits 1/2 if no children exist, or 1/4 if children exist.',
    wife: 'Inherits 1/4 if no children exist, or 1/8 if children exist (shared if multiple).',
    father: 'Inherits a fixed 1/6 if children exist, plus residue if no male children.',
    mother: 'Inherits 1/3, reduced to 1/6 if children or multiple siblings exist.',
  };

  return explanations[id] || `Receives a share according to the rules of Al-Farā’iḍ.`;
};

const getQuranRef = (id: HeirKey): string => {
  const refs: Partial<Record<HeirKey, string>> = {
    son: '4:11', daughter: '4:11',
    father: '4:11', mother: '4:11',
    husband: '4:12', wife: '4:12',
    maternalBrother: '4:12', maternalSister: '4:12',
    fullSister: '4:176', paternalSister: '4:176'
  };
  return refs[id] || 'Sunnah/Ijma';
};

