import { HeirKey, CalculationResult, DeceasedGender, InheritanceState, FiqhSchool } from '../types';
import { ALL_HEIRS } from '../constants';

/**
 * Al-Farā’iḍ Core Engine
 * Implements Sunni Fiqh logic for inheritance.
 */

export const calculateInheritance = (state: InheritanceState): CalculationResult[] => {
  const { totalEstate, deceasedGender, heirs, school } = state;
  let results: CalculationResult[] = [];

  const activeHeirs = { ...heirs };
  if (deceasedGender === DeceasedGender.Male) activeHeirs.husband = 0;
  if (deceasedGender === DeceasedGender.Female) activeHeirs.wife = 0;

  const hasSon = (activeHeirs.son || 0) > 0;
  const hasGrandson = (activeHeirs.grandson || 0) > 0;
  const hasMaleDescendant = hasSon || hasGrandson;
  const hasDaughter = (activeHeirs.daughter || 0) > 0;
  const hasGranddaughter = (activeHeirs.granddaughter || 0) > 0;
  const hasDescendant = hasMaleDescendant || hasDaughter || hasGranddaughter;

  const hasFather = (activeHeirs.father || 0) > 0;
  const hasGrandfather = (activeHeirs.grandfather || 0) > 0;
  const hasMother = (activeHeirs.mother || 0) > 0;

  const sibCount = (activeHeirs.fullBrother || 0) + (activeHeirs.fullSister || 0) +
                   (activeHeirs.paternalBrother || 0) + (activeHeirs.paternalSister || 0) +
                   (activeHeirs.maternalBrother || 0) + (activeHeirs.maternalSister || 0);

  const blocked: Partial<Record<HeirKey, string>> = {};

  // --- HAJB (Blocking) Logic ---
  if (hasFather) {
    blocked.grandfather = 'Father';
    blocked.paternalGrandmother = 'Father';
  }
  if (hasMother) {
    blocked.paternalGrandmother = 'Mother';
    blocked.maternalGrandmother = 'Mother';
  }
  if (hasSon) {
    blocked.grandson = 'Son';
    blocked.granddaughter = 'Son';
    blocked.fullBrother = 'Son';
    blocked.fullSister = 'Son';
    blocked.paternalBrother = 'Son';
    blocked.paternalSister = 'Son';
    blocked.maternalBrother = 'Son';
    blocked.maternalSister = 'Son';
  }
  if (hasGrandson && !hasSon) {
    blocked.fullBrother = 'Grandson';
    blocked.fullSister = 'Grandson';
    blocked.paternalBrother = 'Grandson';
    blocked.paternalSister = 'Grandson';
    blocked.maternalBrother = 'Grandson';
    blocked.maternalSister = 'Grandson';
  }
  if (hasFather) {
    blocked.maternalBrother = 'Father';
    blocked.maternalSister = 'Father';
    blocked.fullBrother = 'Father';
    blocked.fullSister = 'Father';
    blocked.paternalBrother = 'Father';
    blocked.paternalSister = 'Father';
  }
  if (hasGrandfather && !hasFather) {
    blocked.maternalBrother = 'Grandfather';
    blocked.maternalSister = 'Grandfather';
    if (school === FiqhSchool.Hanafi) {
      blocked.fullBrother = 'Grandfather';
      blocked.fullSister = 'Grandfather';
      blocked.paternalBrother = 'Grandfather';
      blocked.paternalSister = 'Grandfather';
    }
  }
  if (hasSon || hasGrandson || hasFather) {
    blocked.nephewFull = 'Male Heir in Direct Line';
    blocked.nephewPaternal = 'Male Heir in Direct Line';
    blocked.uncleFull = 'Male Heir in Direct Line';
    blocked.unclePaternal = 'Male Heir in Direct Line';
    blocked.cousinFull = 'Male Heir in Direct Line';
    blocked.cousinPaternal = 'Male Heir in Direct Line';
  }
  if ((activeHeirs.fullBrother || 0) > 0) {
    blocked.paternalBrother = 'Full Brother';
    blocked.paternalSister = 'Full Brother';
  }
  if (hasDaughter || hasGranddaughter) {
    if ((activeHeirs.fullSister || 0) > 0) {
      blocked.paternalBrother = 'Full Sister (Acting as Residuary)';
      blocked.paternalSister = 'Full Sister (Acting as Residuary)';
    }
  }

  const shares: Partial<Record<HeirKey, number>> = {};
  const categoryMap: Partial<Record<HeirKey, 'Sharer' | 'Residuary'>> = {};
  let totalFurud = 0;

  // Husband / Wife
  if (activeHeirs.husband > 0 && !blocked.husband) {
    shares.husband = hasDescendant ? 1/4 : 1/2;
    categoryMap.husband = 'Sharer';
    totalFurud += shares.husband;
  }
  if (activeHeirs.wife > 0 && !blocked.wife) {
    shares.wife = hasDescendant ? 1/8 : 1/4;
    categoryMap.wife = 'Sharer';
    totalFurud += shares.wife;
  }

  // Parents
  if (hasFather) {
    if (hasMaleDescendant) {
      shares.father = 1/6;
      categoryMap.father = 'Sharer';
      totalFurud += 1/6;
    }
  }
  if (hasMother) {
    shares.mother = (hasDescendant || sibCount >= 2) ? 1/6 : 1/3;
    categoryMap.mother = 'Sharer';
    totalFurud += shares.mother;
  }

  // Daughters
  if (hasDaughter && !hasSon) {
    shares.daughter = activeHeirs.daughter === 1 ? 1/2 : 2/3;
    categoryMap.daughter = 'Sharer';
    totalFurud += shares.daughter;
  }

  if (totalFurud > 1) {
    Object.keys(shares).forEach(k => { shares[k as HeirKey]! /= totalFurud; });
    totalFurud = 1;
  }

  let residue = 1 - totalFurud;
  if (residue > 1e-6) {
    const asabaList: HeirKey[] = [];
    if (hasSon) { asabaList.push('son'); if (hasDaughter) asabaList.push('daughter'); }
    else if (hasGrandson) { asabaList.push('grandson'); if (hasGranddaughter) asabaList.push('granddaughter'); }
    else if (hasFather) { asabaList.push('father'); }
    else if (hasGrandfather && !blocked.grandfather) { asabaList.push('grandfather'); }
    else if ((activeHeirs.fullBrother || 0) > 0) { asabaList.push('fullBrother'); if ((activeHeirs.fullSister || 0) > 0) asabaList.push('fullSister'); }

    if (asabaList.length > 0) {
      let totalWeight = 0;
      asabaList.forEach(k => {
        const weight = ALL_HEIRS.find(h => h.id === k)?.gender === 'M' ? 2 : 1;
        totalWeight += weight * activeHeirs[k];
      });
      asabaList.forEach(k => {
        const weight = ALL_HEIRS.find(h => h.id === k)?.gender === 'M' ? 2 : 1;
        const s = (residue * weight) / totalWeight;
        shares[k] = (shares[k] || 0) + s * activeHeirs[k];
        categoryMap[k] = 'Residuary';
      });
      residue = 0;
    }
  }

  if (residue > 1e-6) {
    const raddRecipients = Object.keys(shares).filter(k => k !== 'husband' && k !== 'wife');
    if (raddRecipients.length > 0) {
      const raddTotal = raddRecipients.reduce((sum, k) => sum + (shares[k as HeirKey] || 0), 0);
      raddRecipients.forEach(k => { shares[k as HeirKey]! += (shares[k as HeirKey]! / raddTotal) * residue; });
    }
  }

  ALL_HEIRS.forEach(def => {
    const count = activeHeirs[def.id] || 0;
    const isBlocked = !!blocked[def.id];
    if (count > 0 || isBlocked) {
      const share = shares[def.id] || 0;
      results.push({
        heirId: def.id,
        heirName: `${def.nameEn} (${def.nameAr})`,
        count,
        shareFraction: formatFraction(share),
        sharePercentage: share * 100,
        shareAmount: share * totalEstate,
        isBlocked,
        blockedBy: blocked[def.id],
        explanation: getDetailedExplanation(def.id, isBlocked, blocked[def.id], share > 0, categoryMap[def.id], school),
        quranReference: getQuranRef(def.id),
        heirType: isBlocked ? 'Blocked' : (categoryMap[def.id] || 'Sharer')
      });
    }
  });

  return results;
};

const formatFraction = (val: number): string => {
  if (val < 1e-6) return '0';
  const denominators = [2, 3, 4, 6, 8, 12, 13, 15, 17, 24, 27];
  for (const d of denominators) {
    const n = Math.round(val * d);
    if (Math.abs(val - n / d) < 1e-4) return `${n}/${d}`;
  }
  return val.toFixed(4);
};

const getDetailedExplanation = (id: HeirKey, isBlocked: boolean, blockedBy: string | undefined, hasShare: boolean, type: string | undefined, school: FiqhSchool): string => {
  if (isBlocked) return `Excluded (Hajb Hirman) from the inheritance because of the presence of the ${blockedBy}. In Islamic law, closer relatives typically block more distant ones.`;
  if (!hasShare) return `Inherits zero in this calculation because the estate was fully exhausted by higher priority sharers (Ashab-ul-Furud).`;

  const base = {
    husband: "Inherits as a primary sharer. Since there are children/descendants, the share is 1/4, otherwise 1/2.",
    wife: "Inherits as a primary sharer. Since there are children/descendants, the share is 1/8, otherwise 1/4.",
    son: "Inherits as a Residuary (Asaba), receiving twice the share of a daughter.",
    daughter: type === 'Residuary' ? "Inherits as a Residuary (Asaba) along with her brother(s)." : "Inherits as a primary sharer (1/2 if alone, 2/3 if multiple).",
    father: type === 'Residuary' ? "Inherits as a Residuary because there are no male descendants." : "Inherits a fixed 1/6 share because male descendants exist.",
    mother: "Inherits a fixed share. Reduced to 1/6 due to the presence of descendants or multiple siblings.",
  };

  const schoolContext = id === 'grandfather' && school !== FiqhSchool.Hanafi ? " (According to the Jamhur/Majority view, the Grandfather shares with siblings)." : "";

  return (base as any)[id] || `Receives a share according to the standard rules of Sunni Fiqh.${schoolContext}`;
};

const getQuranRef = (id: HeirKey): string => {
  const refs: Partial<Record<HeirKey, string>> = {
    son: '4:11', daughter: '4:11', father: '4:11', mother: '4:11',
    husband: '4:12', wife: '4:12', maternalBrother: '4:12', maternalSister: '4:12',
    fullSister: '4:176', paternalSister: '4:176'
  };
  return refs[id] || 'Sunnah/Ijma';
};

