  }, [state.language]);

  // --- Handlers ---
  const handleHeirChange = (key: HeirKey, value: number) => {
    setState(prev => ({
      ...prev,
      heirs: { ...prev.heirs, [key]: value }
    }));
  };

  const resetAll = () => {
    setState({
      totalEstate: 100000,
