                  <input 
                    type="number" 
                    value={state.totalEstate} 
                    onChange={(e) => setState({...state, totalEstate: Number(e.target.value)})}
                    className="w-full bg-amber-50 dark:bg-amber-900/10 border-2 border-amber-100 dark:border-amber-900/20 rounded-2xl py-4 px-5 font-black text-2xl text-amber-900 dark:text-amber-100 focus:ring-2 focus:ring-amber-500 outline-none transition-all"
                  />
                  <div className="absolute right-5 top-1/2 -translate-y-1/2 text-amber-600 font-bold text-lg pointer-events-none opacity-50">
