                      <p className="text-3xl font-black text-amber-700 dark:text-amber-100">
                        {state.totalEstate.toLocaleString()} <span className="text-sm font-bold opacity-60">{state.currency}</span>
                      </p>
                    </div>
                  </div>
                </div>
              </div>

              {/* Visual Hierarchy */}
              <div className="bg-white dark:bg-slate-800 p-6 rounded-3xl shadow-sm border border-slate-200 dark:border-slate-700">
                <h2 className="text-lg font-bold mb-4 flex items-center gap-2">
                  <Network className="text-blue-500" size={20} />
                  {t.familyTree}
                </h2>
                <FamilyTree results={results} deceasedGender={state.deceasedGender} currency={state.currency} />
              </div>

              {/* Dynamic explanations & Table */}
              <ResultExplanations results={results} t={t} />
            </>
          )}
        </div>
      </main>

      <footer className="max-w-6xl mx-auto mt-20 pt-10 border-t border-slate-200 dark:border-slate-800 text-center no-print">
        <p className="text-slate-400 text-sm font-medium">
          &copy; {new Date().getFullYear()} {t.title}.
        </p>
      </footer>
    </div>
  );
};

