      <footer className="max-w-6xl mx-auto mt-24 pt-10 border-t border-slate-200 dark:border-slate-800 text-center no-print">
        <p className="text-slate-400 text-sm font-black tracking-widest uppercase">
          &copy; {new Date().getFullYear()} {t.title} Analysis System
        </p>
