import React, { useState, useMemo, useEffect } from 'react';
import { 
  InheritanceState, 
  DeceasedGender, 
  FiqhSchool, 
  HeirKey, 
  CalculationResult 
} from './types';
import { 
  CURRENCIES, 
  LANGUAGES, 
  MALE_HEIRS, 
  FEMALE_HEIRS, 
  i18nStrings,
  CurrencyInfo
} from './constants';
