        <div className="flex items-center gap-4">
          <div className="bg-orange-500 p-3 rounded-2xl shadow-2xl shadow-orange-500/30 dark:shadow-none transition-transform hover:scale-105 active:scale-95 cursor-pointer">
            <Landmark className="text-white w-9 h-9" />
          </div>
          <div>
            <h1 className="text-4xl font-black tracking-tighter font-arabic leading-none">{t.title}</h1>
            <p className="text-orange-500 text-xs font-black uppercase tracking-[0.3em] mt-1">{t.subtitle}</p>
          </div>
        </div>

        <div className="flex flex-wrap items-center justify-center gap-4 no-print">
          <button onClick={toggleDarkMode} className="p-3 bg-white dark:bg-slate-800 shadow-lg border border-slate-200 dark:border-slate-700 rounded-2xl hover:bg-slate-50 dark:hover:bg-slate-700 transition-all active:scale-90">
            {darkMode ? <Sun size={24} className="text-yellow-400" /> : <Moon size={24} className="text-blue-500" />}
          </button>

          <div className="flex items-center gap-3 bg-white dark:bg-slate-800 p-3 rounded-2xl shadow-lg border border-slate-200 dark:border-slate-700">
            <Coins size={20} className="text-orange-500" />
            <select 
              value={state.currency} 
              onChange={(e) => setState({...state, currency: e.target.value})}
              className="bg-transparent border-none text-sm font-black focus:ring-0 pr-10 cursor-pointer"
            >
              {CURRENCIES.map(c => {
                const translatedName = t.currencies?.[c.code] || c.nameEn;
                return (
                  <option key={c.code} value={c.code}>
