            <Globe size={20} className="text-blue-500" />
            <select 
              value={state.language} 
              onChange={(e) => setState({...state, language: e.target.value})}
              className="bg-transparent border-none text-sm font-black focus:ring-0 pr-10 cursor-pointer"
            >
              {sortedLanguages.map(l => <option key={l.code} value={l.code}>{l.name}</option>)}
            </select>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-12">
        {/* Left Input Panel */}
        <div className="lg:col-span-5 space-y-8 no-print">
          <section className="bg-white dark:bg-slate-800 p-10 rounded-[3rem] shadow-2xl shadow-slate-200/50 dark:shadow-none border border-slate-100 dark:border-slate-700">
