                </div>
              </div>

              <div>
                <label className="block text-[11px] font-black uppercase text-slate-400 mb-3 tracking-[0.2em]">{t.deceasedGender}</label>
                <div className="flex p-3 bg-slate-100 dark:bg-slate-900 rounded-[2rem] border-2 border-slate-200 dark:border-slate-700">
