                      <p className="text-6xl font-black flex items-baseline gap-4">
                        {state.totalEstate.toLocaleString()}
                        <span className="text-2xl font-bold opacity-70">{state.currency}</span>
                      </p>
                    </div>
                    <div className="flex gap-6">
                      <div className="flex-1 bg-slate-50 dark:bg-slate-900 p-6 rounded-3xl border border-slate-100 dark:border-slate-800">
                        <p className="text-[12px] font-black text-slate-400 uppercase tracking-widest mb-3">School</p>
                        <p className="text-xl font-black">{state.school}</p>
                      </div>
                      <div className="flex-1 bg-slate-50 dark:bg-slate-900 p-6 rounded-3xl border border-slate-100 dark:border-slate-800">
                        <p className="text-[12px] font-black text-slate-400 uppercase tracking-widest mb-3">Gender</p>
                        <p className="text-xl font-black">{state.deceasedGender}</p>
                      </div>
                    </div>
                  </div>
                </div>
              </div>

              {/* Visual Tree */}
              <div className="bg-white dark:bg-slate-800 p-10 rounded-[3.5rem] shadow-2xl shadow-slate-200/50 dark:shadow-none border border-slate-100 dark:border-slate-700">
                <h2 className="text-2xl font-black mb-10 flex items-center gap-4">
                  <Network className="text-blue-500" size={28} />
                  {t.familyTree}
                </h2>
                <FamilyTree results={results} deceasedGender={state.deceasedGender} currency={state.currency} />
              </div>

              {/* Explanations and Data table */}
              <ResultExplanations results={results} t={t} />
            </div>
          )}
        </div>
      </main>

      <footer className="max-w-7xl mx-auto mt-32 pt-12 border-t border-slate-200 dark:border-slate-800 text-center no-print pb-10">
        <p className="text-slate-400 text-sm font-black tracking-[0.4em] uppercase opacity-60">
          &copy; {new Date().getFullYear()} {t.title} • Jurisprudential Analysis Engine
        </p>
      </footer>
    </div>
  );
};

