import React, { useState, useMemo, useEffect } from 'react';
import { 
  InheritanceState, 
  DeceasedGender, 
  FiqhSchool, 
  HeirKey, 
  CalculationResult 
} from './types';
import { 
  CURRENCIES, 
  LANGUAGES, 
  MALE_HEIRS, 
  FEMALE_HEIRS, 
  i18nStrings 
} from './constants';
import { calculateInheritance } from './logic/calculator';
import { FamilyTree } from './FamilyTree';
import { ResultExplanations } from './ResultExplanations';
import { 
  PieChart, Pie, Cell, ResponsiveContainer, Tooltip 
} from 'recharts';
import { 
  Calculator, Users, Globe, Landmark, 
  ArrowRight, RotateCcw, Printer, Moon, Sun, 
  Info, Network, Coins
} from 'lucide-react';

const COLORS = ['#f59e0b', '#3b82f6', '#8b5cf6', '#10b981', '#ef4444', '#ec4899', '#06b6d4', '#84cc16'];

const App: React.FC = () => {
  const [state, setState] = useState<InheritanceState>({
    totalEstate: 0, 
    currency: 'USD',
    deceasedGender: DeceasedGender.Male,
    school: FiqhSchool.Hanafi,
    language: 'en',
    heirs: {} as Record<HeirKey, number>
  });

  const [darkMode, setDarkMode] = useState(false);
  const [isCalculated, setIsCalculated] = useState(false);

  const t = i18nStrings[state.language] || i18nStrings.en;

  const results = useMemo(() => {
    return calculateInheritance(state);
  }, [state]);

  const chartData = useMemo(() => {
    return results
      .filter(r => r.shareAmount > 0)
      .map(r => ({ name: r.heirName, value: r.shareAmount }));
  }, [results]);

  const sortedLanguages = useMemo(() => {
    const selected = LANGUAGES.find(l => l.code === state.language);
    const others = LANGUAGES.filter(l => l.code !== state.language);
    return selected ? [selected, ...others] : LANGUAGES;
  }, [state.language]);

  const handleHeirChange = (key: HeirKey, value: number) => {
    setState(prev => ({
      ...prev,
      heirs: { ...prev.heirs, [key]: Math.max(0, value) }
    }));
  };

  const resetAll = () => {
    setState({
      ...state,
      totalEstate: 0,
      heirs: {} as Record<HeirKey, number>
    });
    setIsCalculated(false);
  };

  const toggleDarkMode = () => setDarkMode(!darkMode);
  const handlePrint = () => window.print();

  useEffect(() => {
    const body = document.body;
    if (darkMode) {
      body.classList.add('bg-slate-900', 'text-slate-100');
      body.classList.remove('bg-slate-50', 'text-slate-900');
    } else {
      body.classList.remove('bg-slate-900', 'text-slate-100');
      body.classList.add('bg-slate-50', 'text-slate-900');
    }
  }, [darkMode]);

  const getHeirLabel = (h: any) => {
    const translatedName = t.heirs?.[h.id] || h.nameEn;
    return `${translatedName} (${h.nameAr})`;
  };

  const currentCurrencySymbol = CURRENCIES.find(c => c.code === state.currency)?.symbol || '$';

  return (
    <div className={`min-h-screen pb-20 px-4 md:px-8 transition-colors duration-300 font-black ${darkMode ? 'dark text-white' : 'text-slate-900'}`}>
      {/* Header */}
      <header className="max-w-7xl mx-auto py-8 flex flex-col md:flex-row justify-between items-center gap-6">
        <div className="flex items-center gap-4">
          <div className="bg-orange-500 p-3 rounded-2xl shadow-2xl shadow-orange-500/30 dark:shadow-none transition-transform hover:scale-105 active:scale-95 cursor-pointer">
            <Landmark className="text-white w-9 h-9" />
          </div>
          <div>
            <h1 className="text-4xl font-black tracking-tighter font-arabic leading-none">{t.title}</h1>
            <p className="text-orange-500 text-xs font-black uppercase tracking-[0.3em] mt-1">{t.subtitle}</p>
          </div>
        </div>

        {/* Parallel Layout for Currency and Language on ALL devices */}
        <div className="grid grid-cols-2 md:flex items-center gap-2 md:gap-4 no-print w-full md:w-auto">
          <div className="flex items-center gap-2 bg-white dark:bg-slate-800 p-2.5 rounded-2xl shadow-lg border border-slate-200 dark:border-slate-700">
            <Coins size={18} className="text-orange-500 shrink-0" />
            <select 
              value={state.currency} 
              onChange={(e) => setState({...state, currency: e.target.value})}
              className="bg-transparent border-none text-[11px] md:text-sm font-black focus:ring-0 w-full cursor-pointer pr-4"
            >
              {CURRENCIES.map(c => {
                const translatedName = t.currencies?.[c.code] || c.nameEn;
                return (
                  <option key={c.code} value={c.code} className="text-slate-900">
                    {c.symbol} {c.nameEn} ({translatedName})
                  </option>
                );
              })}
            </select>
          </div>

          <div className="flex items-center gap-2 bg-white dark:bg-slate-800 p-2.5 rounded-2xl shadow-lg border border-slate-200 dark:border-slate-700">
            <Globe size={18} className="text-blue-500 shrink-0" />
            <select 
              value={state.language} 
              onChange={(e) => setState({...state, language: e.target.value})}
              className="bg-transparent border-none text-[11px] md:text-sm font-black focus:ring-0 w-full cursor-pointer pr-4"
            >
              {sortedLanguages.map(l => <option key={l.code} value={l.code} className="text-slate-900">{l.name}</option>)}
            </select>
          </div>

          <button 
            onClick={toggleDarkMode} 
            className="col-span-2 md:col-auto p-3 bg-white dark:bg-slate-800 shadow-lg border border-slate-200 dark:border-slate-700 rounded-2xl hover:bg-slate-50 dark:hover:bg-slate-700 transition-all active:scale-90 flex justify-center items-center"
          >
            {darkMode ? <Sun size={24} className="text-yellow-400" /> : <Moon size={24} className="text-blue-500" />}
          </button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-8 md:gap-12">
        {/* Left Input Panel */}
        <div className="lg:col-span-5 space-y-8 no-print">
          <section className="bg-white dark:bg-slate-800 p-6 md:p-10 rounded-[3rem] shadow-2xl shadow-slate-200/50 dark:shadow-none border border-slate-100 dark:border-slate-700">
            <h2 className="text-2xl font-black mb-8 flex items-center gap-4">
              <Calculator className="text-orange-500" size={28} />
              {t.summary}
            </h2>

            <div className="space-y-8">
              {/* Parallel Layout for Amount and Fiqh on ALL devices */}
              <div className="grid grid-cols-2 gap-4 md:gap-8">
                <div>
                  <label className="block text-[10px] md:text-[11px] font-black uppercase text-slate-400 mb-2 tracking-[0.1em]">{t.distributionAmount}</label>
                  <div className="relative">
                    <input 
                      type="number" 
                      value={state.totalEstate || ''} 
                      placeholder="0"
                      onChange={(e) => setState({...state, totalEstate: Number(e.target.value)})}
                      className="w-full bg-orange-50/40 dark:bg-orange-500/5 border-2 md:border-4 border-orange-100 dark:border-orange-500/20 rounded-2xl md:rounded-3xl py-4 md:py-6 px-4 md:px-8 font-black text-xl md:text-3xl text-orange-600 dark:text-orange-100 focus:border-orange-500 outline-none transition-all placeholder-orange-200"
                    />
                    <div className="absolute right-4 md:right-8 top-1/2 -translate-y-1/2 text-orange-400 font-black text-sm md:text-2xl opacity-60 pointer-events-none">
                      {currentCurrencySymbol}
                    </div>
                  </div>
                </div>

                <div>
                  <label className="block text-[10px] md:text-[11px] font-black uppercase text-slate-400 mb-2 tracking-[0.1em]">{t.fiqhSchool}</label>
                  <select 
                    value={state.school} 
                    onChange={(e) => setState({...state, school: e.target.value as FiqhSchool})}
                    className="w-full h-[60px] md:h-[84px] bg-slate-100 dark:bg-slate-900 border-none rounded-2xl md:rounded-3xl px-4 md:px-8 font-black text-sm md:text-lg focus:ring-4 focus:ring-orange-500 transition-all"
                  >
                    {Object.values(FiqhSchool).map(s => <option key={s} value={s} className="text-slate-900">{s}</option>)}
                  </select>
                </div>
              </div>

              <div>
                <label className="block text-[10px] md:text-[11px] font-black uppercase text-slate-400 mb-3 tracking-[0.1em]">{t.deceasedGender}</label>
                <div className="flex p-2 bg-slate-100 dark:bg-slate-900 rounded-[1.5rem] md:rounded-[2rem] border-2 border-slate-200 dark:border-slate-700">
                  <button 
                    onClick={() => setState({...state, deceasedGender: DeceasedGender.Male})}
                    className={`flex-1 py-3 md:py-5 text-sm md:text-lg font-black rounded-xl md:rounded-2xl transition-all ${state.deceasedGender === DeceasedGender.Male ? 'bg-orange-500 shadow-2xl text-white scale-[1.03]' : 'text-slate-400 hover:text-slate-600'}`}
                  >
                    {t.male}
                  </button>
                  <button 
                    onClick={() => setState({...state, deceasedGender: DeceasedGender.Female})}
                    className={`flex-1 py-3 md:py-5 text-sm md:text-lg font-black rounded-xl md:rounded-2xl transition-all ${state.deceasedGender === DeceasedGender.Female ? 'bg-orange-500 shadow-2xl text-white scale-[1.03]' : 'text-slate-400 hover:text-slate-600'}`}
                  >
                    {t.female}
                  </button>
                </div>
              </div>
            </div>
          </section>

          <section className="bg-white dark:bg-slate-800 p-6 md:p-10 rounded-[3rem] shadow-2xl shadow-slate-200/50 dark:shadow-none border border-slate-100 dark:border-slate-700">
            <h2 className="text-2xl font-black mb-10 flex items-center gap-4">
              <Users className="text-orange-500" size={28} />
              {t.heirsSelection}
            </h2>

            <div className="grid grid-cols-2 gap-4 md:gap-6">
              {(state.deceasedGender === DeceasedGender.Male ? FEMALE_HEIRS : MALE_HEIRS).map(h => {
                if (h.id === 'husband' || h.id === 'wife') {
                  return (
                    <div key={h.id} className="bg-slate-50 dark:bg-slate-900 p-4 md:p-5 rounded-[1.5rem] md:rounded-[2rem] border-2 border-slate-100 dark:border-slate-800 transition-all hover:border-orange-500 hover:bg-white dark:hover:bg-slate-800 group">
                      <label className="block text-[11px] md:text-[12px] font-black text-slate-500 group-hover:text-orange-500 uppercase mb-2 md:mb-3 font-arabic leading-tight">
                        {getHeirLabel(h)}
                      </label>
                      <input 
                        type="number" min="0" max={h.id === 'wife' ? 4 : 1}
                        value={state.heirs[h.id] || 0}
                        onChange={(e) => handleHeirChange(h.id, Number(e.target.value))}
                        className="w-full bg-white dark:bg-slate-800 border-2 md:border-4 border-slate-100 dark:border-slate-700 rounded-xl md:rounded-2xl text-lg md:text-2xl font-black py-2 md:py-3 px-3 md:px-5 focus:border-orange-500 outline-none transition-all"
                      />
                    </div>
