        </text>
        <text
          x={pos.x}
          y={pos.y + (share ? 4 : 10)}
          textAnchor="middle"
          dominantBaseline="middle"
          fill={textColor}
          className="text-[11px] font-arabic font-bold opacity-70"
        >
          {label.includes('(') ? label.substring(label.indexOf('(')) : ''}
        </text>
        {share && !isBlocked && (
          <text
            x={pos.x}
            y={pos.y + 24}
            textAnchor="middle"
            dominantBaseline="middle"
            fill={textColor}
            className="text-[14px] font-black"
          >
            {share}
          </text>
        )}
        {isBlocked && (
          <text
            x={pos.x}
            y={pos.y + 24}
            textAnchor="middle"
            dominantBaseline="middle"
            fill="#ef4444"
            className="text-[9px] font-black uppercase tracking-widest"
          >
            Blocked
          </text>
        )}
      </g>
    );
  };

  const renderConnection = (fromId: string, toId: string) => {
    const from = positions[fromId];
    const to = positions[toId];
    if (!from || !to) return null;

    return (
      <line
        key={`${fromId}-${toId}`}
        x1={from.x}
        y1={from.y}
        x2={to.x}
        y2={to.y}
        stroke="#cbd5e1"
        strokeWidth="2"
        strokeDasharray="6 4"
        className="opacity-40"
      />
    );
  };

  return (
    <div className="w-full overflow-hidden bg-white rounded-[2.5rem] border border-slate-100 p-8 shadow-inner">
      <svg viewBox="0 0 800 600" className="w-full h-auto">
        {/* Background Connections */}
        {activeResults.map(r => renderConnection('deceased', r.heirId))}

        {/* Deceased Center */}
        {renderNode('deceased', `Deceased (${deceasedGender})`)}

        {/* Dynamic Heirs */}
        {activeResults.map(r => 
          renderNode(r.heirId, r.heirName, `${r.sharePercentage.toFixed(1)}%`, r.isBlocked)
        )}
      </svg>
    </div>
  );
};

