import React from 'react';
import { HeirKey, CalculationResult, DeceasedGender } from './types';
import { i18nStrings } from './constants';

interface FamilyTreeProps {
  results: CalculationResult[];
  deceasedGender: DeceasedGender;
  currency: string;
  language: string;
}

export const FamilyTree: React.FC<FamilyTreeProps> = ({ results, deceasedGender, language }) => {
  const nodeWidth = 175;
  const nodeHeight = 105;
  const t = i18nStrings[language] || i18nStrings.en;

  const positions: Record<string, { x: number; y: number }> = {
    grandfather: { x: 150, y: 80 },
    paternalGrandmother: { x: 350, y: 80 },
    maternalGrandmother: { x: 750, y: 80 },

    father: { x: 250, y: 220 },
    mother: { x: 650, y: 220 },

    deceased: { x: 450, y: 400 },
    husband: { x: 750, y: 400 },
    wife: { x: 750, y: 400 },

    fullBrother: { x: 100, y: 300 },
    fullSister: { x: 100, y: 500 },
    paternalBrother: { x: 250, y: 360 },
    paternalSister: { x: 250, y: 460 },
    maternalBrother: { x: 650, y: 360 },
    maternalSister: { x: 650, y: 460 },

    son: { x: 300, y: 620 },
    daughter: { x: 600, y: 620 },

    grandson: { x: 300, y: 780 },
    granddaughter: { x: 600, y: 780 },

    nephewFull: { x: 880, y: 580 },
    nephewPaternal: { x: 880, y: 680 },
    uncleFull: { x: 920, y: 150 },
    unclePaternal: { x: 920, y: 250 },
    cousinFull: { x: 920, y: 800 },
    cousinPaternal: { x: 920, y: 900 },

    governmentTreasury: { x: 525, y: 880 }
  };

  const activeResults = results.filter(r => r.count > 0 || r.isBlocked || r.heirId === 'governmentTreasury');

  const sortedHeirs = [...activeResults].sort((a, b) => {
    if (a.isBlocked && !b.isBlocked) return -1;
    if (!a.isBlocked && b.isBlocked) return 1;
    return 0;
  });

  const renderNode = (heir: CalculationResult | { id: 'deceased', label: string }) => {
    const isDeceased = 'id' in heir;
    const id = isDeceased ? 'deceased' : (heir as CalculationResult).heirId;
    const pos = positions[id];
    if (!pos) return null;

    const x = pos.x - nodeWidth / 2;
    const y = pos.y - nodeHeight / 2;

    const isBlocked = !isDeceased && (heir as CalculationResult).isBlocked;
    const count = !isDeceased ? (heir as CalculationResult).count : 1;
    const label = isDeceased ? (heir as any).label : (heir as CalculationResult).heirName;
    const totalShare = !isDeceased && !isBlocked ? `${(heir as CalculationResult).sharePercentage.toFixed(1)}%` : null;

    let bgColor = isDeceased ? '#1e293b' : isBlocked ? '#fef2f2' : '#f0fdf4';
    let borderColor = isDeceased ? '#0f172a' : isBlocked ? '#ef4444' : '#22c55e';
    let textColor = isDeceased ? '#ffffff' : isBlocked ? '#991b1b' : '#166534';

    if (id === 'governmentTreasury') {
      bgColor = '#fff7ed';
      borderColor = '#ea580c';
      textColor = '#9a3412';
    }

    return (
      <g key={id} className="transition-all duration-300 pointer-events-none">
        <rect
          x={x}
          y={y}
          width={nodeWidth}
          height={nodeHeight}
          rx="32"
          fill={bgColor}
          stroke={borderColor}
          strokeWidth="4"
          className="drop-shadow-lg"
        />
        <text
          x={pos.x}
          y={pos.y - (totalShare ? 20 : 0)}
          textAnchor="middle"
          dominantBaseline="middle"
          fill={textColor}
          className="text-[10px] font-black uppercase tracking-wider"
        >
          {label}
        </text>
        {!isDeceased && count > 1 && (
           <text
            x={pos.x}
            y={pos.y + 10}
            textAnchor="middle"
            dominantBaseline="middle"
            fill={textColor}
            className="text-[9px] font-black uppercase opacity-60 tracking-widest"
          >
            {t.table.count}: {count}
          </text>
        )}
        {totalShare && (
          <text
            x={pos.x}
            y={pos.y + 26}
            textAnchor="middle"
            dominantBaseline="middle"
            fill={textColor}
            className="text-[16px] font-black"
          >
            {totalShare}
          </text>
        )}
        {isBlocked && (
          <text
            x={pos.x}
            y={pos.y + 30}
            textAnchor="middle"
            dominantBaseline="middle"
            fill="#ef4444"
            className="text-[10px] font-black uppercase tracking-widest"
          >
            {t.heirTypes.Blocked}
          </text>
        )}
      </g>
    );
  };

  const renderConnection = (fromId: string, toId: string) => {
    const from = positions[fromId];
    const to = positions[toId];
    if (!from || !to) return null;

    return (
      <path
        key={`${fromId}-${toId}`}
        d={`M ${from.x} ${from.y} L ${to.x} ${to.y}`}
        stroke="#e2e8f0"
        strokeWidth="2"
        fill="none"
        strokeDasharray="8 6"
        className="opacity-40"
      />
    );
  };

  const deceasedStatusLabel = `${t.deceasedGender} (${t[deceasedGender.toLowerCase()]})`;

  return (
    <div className="w-full overflow-x-auto bg-white rounded-[2.5rem] border border-slate-100 p-12 shadow-inner">
      <svg viewBox="0 0 1050 950" className="min-w-[1000px] h-auto">
        {sortedHeirs.map(r => renderConnection('deceased', r.heirId))}
        {sortedHeirs.filter(r => r.isBlocked).map(r => renderNode(r))}
        {renderNode({ id: 'deceased', label: deceasedStatusLabel })}
        {sortedHeirs.filter(r => !r.isBlocked).map(r => renderNode(r))}
      </svg>
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { 
  InheritanceState, 
  DeceasedGender, 
  FiqhSchool, 
  HeirKey 
} from './types';
import { 
  CURRENCIES, 
  LANGUAGES, 
  MALE_HEIRS, 
  FEMALE_HEIRS, 
  i18nStrings 
} from './constants';
import { calculateInheritance } from './logic/calculator';
import { FamilyTree } from './FamilyTree';
import { ResultExplanations } from './ResultExplanations';
import { 
  Calculator, Users, Globe, Landmark, 
  ArrowRight, RotateCcw, Printer, 
  Info, Network, Coins, MinusCircle, AlertTriangle, X, RefreshCw
} from 'lucide-react';

const HEIR_LIMITS: Record<string, number> = {
  husband: 1,
  wife: 4,
  father: 1,
  mother: 1,
  grandfather: 1,
  paternalGrandmother: 1,
  maternalGrandmother: 1
};

const App: React.FC = () => {
  const [state, setState] = useState<InheritanceState>({
    totalEstate: 0, 
    funeralExpenses: 0,
    debts: 0,
    wasiyyat: 0,
    currency: 'USD',
    deceasedGender: DeceasedGender.Male,
    school: FiqhSchool.Hanafi,
    language: 'en',
    heirs: {} as Record<HeirKey, number>
  });

  const [isCalculated, setIsCalculated] = useState(false);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);

  const t = i18nStrings[state.language] || i18nStrings.en;

  // Sorting Languages so the selected is at top
  const sortedLanguages = useMemo(() => {
    return [...LANGUAGES].sort((a, b) => {
      if (a.code === state.language) return -1;
      if (b.code === state.language) return 1;
      return 0;
    });
  }, [state.language]);

  // Currency bilingual labels and sorting
  const formattedCurrencies = useMemo(() => {
    return [...CURRENCIES].map(c => {
      const localizedName = t.currencies[c.code] || c.nameEn;
      const displayLabel = state.language === 'en' 
        ? `${c.nameEn} (${c.symbol})`
        : `${localizedName} / ${c.nameEn} (${c.symbol})`;
      return { ...c, displayLabel };
    }).sort((a, b) => {
       if (a.code === state.currency) return -1;
       if (b.code === state.currency) return 1;
       return 0;
    });
  }, [state.currency, state.language, t.currencies]);

  const results = useMemo(() => {
    return calculateInheritance(state);
  }, [state]);

  const blockedHeirIds = useMemo(() => {
    return new Set(results.filter(r => r.isBlocked).map(r => r.heirId));
  }, [results]);

  const hasSelectedHeirs = useMemo(() => {
    return (Object.values(state.heirs) as number[]).some(count => count > 0);
  }, [state.heirs]);

  const triggerError = (msg: string) => {
    setErrorMessage(msg);
    setTimeout(() => setErrorMessage(null), 5000);
  };

  const resetAll = () => {
    setState({
      totalEstate: 0,
      funeralExpenses: 0,
      debts: 0,
      wasiyyat: 0,
      currency: state.currency,
      deceasedGender: state.deceasedGender,
      school: state.school,
      language: state.language,
      heirs: {} as Record<HeirKey, number>
    });
    setIsCalculated(false);
    setErrorMessage(null);
  };

  const handleHeirChange = (key: HeirKey, value: number) => {
    const max = HEIR_LIMITS[key] || 10;
    if (value > max) {
      triggerError(`Maximum limit for ${t.heirs?.[key] || key} is ${max}.`);
      return;
    }
    const val = Math.max(0, value);

    setState(prev => {
      const newHeirs = { ...prev.heirs, [key]: val };
      const currentlyHasHeirs = (Object.values(newHeirs) as number[]).some(c => c > 0);

      let updatedWasiyyat = prev.wasiyyat;
      if (currentlyHasHeirs && prev.wasiyyat > prev.totalEstate / 3) {
        updatedWasiyyat = 0;
        triggerError("Wasiyyat reset to 0 because heirs are present (limit is 1/3).");
      }

      return {
        ...prev,
        heirs: newHeirs,
        wasiyyat: updatedWasiyyat
      };
    });
    setIsCalculated(false);
  };

  const handleNumericInput = (field: keyof InheritanceState, value: number) => {
    if (value < 0) return;

    if (field === 'totalEstate' && (value === 0 || isNaN(value))) {
      resetAll();
      return;
    }

    if (field === 'wasiyyat') {
      const isHanafi = state.school === FiqhSchool.Hanafi;
      const limitFactor = (isHanafi && !hasSelectedHeirs) ? 1 : (1/3);
      const maxWasiyyat = state.totalEstate * limitFactor;

      if (value > maxWasiyyat) {
        const limitLabel = limitFactor === 1 ? "100%" : "1/3";
        triggerError(`Wasiyyat cannot exceed ${limitLabel} of estate (${maxWasiyyat.toLocaleString()} ${state.currency}).`);
        return;
      }
    }

    setState(prev => ({ ...prev, [field]: value }));
    setIsCalculated(false);
  };

  const handlePrint = () => window.print();

  const getHeirLabel = (h: any) => {
    const translatedName = t.heirs?.[h.id] || h.nameEn;
    const limit = HEIR_LIMITS[h.id] ? `(0-${HEIR_LIMITS[h.id]})` : '';
    return `${translatedName} ${limit}`;
  };

  const currentCurrencySymbol = CURRENCIES.find(c => c.code === state.currency)?.symbol || '$';

  const renderHeirInput = (h: any) => {
    const count = state.heirs[h.id] || 0;
    const isFilled = count > 0;
    const isBlocked = blockedHeirIds.has(h.id);
    const blocker = results.find(r => r.heirId === h.id)?.blockedBy;

    let containerClass = "p-4 md:p-5 rounded-[2rem] border-4 transition-all group ";
    let labelClass = "block text-[10px] font-black uppercase mb-2 md:mb-3 leading-tight ";
    let inputClass = "w-full border-none rounded-xl text-lg md:text-2xl font-black py-2 md:py-3 px-3 md:px-5 outline-none transition-all shadow-inner ";

    if (isBlocked) {
      containerClass += "bg-red-50 border-red-500 shadow-lg shadow-red-100 scale-[0.98]";
      labelClass += "text-red-700";
      inputClass += "bg-white text-red-800 focus:ring-2 focus:ring-red-500 opacity-50 cursor-not-allowed";
    } else if (isFilled) {
      containerClass += "bg-green-50 border-green-500 shadow-lg shadow-green-100";
      labelClass += "text-green-700";
      inputClass += "bg-white text-green-700";
    } else {
      containerClass += "bg-slate-50 border-slate-50 hover:border-orange-200";
      labelClass += "text-slate-500";
      inputClass += "bg-white text-slate-800 focus:ring-2 focus:ring-orange-500";
    }

    return (
      <div key={h.id} className={containerClass}>
        <label className={labelClass}>
          {getHeirLabel(h)}
          {isBlocked && blocker && <span className="block text-[8px] mt-1 font-black">({t.blockedBy} {blocker})</span>}
        </label>
        <input 
          type="number" 
          min="0" 
          value={count || ''}
          placeholder="0"
          disabled={isBlocked}
          onChange={(e) => handleHeirChange(h.id, Number(e.target.value))}
          className={inputClass}
        />
      </div>
    );
