import React from 'react';
import { HeirKey, CalculationResult, DeceasedGender } from './types';
import { i18nStrings } from './constants';

interface FamilyTreeProps {
  results: CalculationResult[];
  deceasedGender: DeceasedGender;
  currency: string;
  language: string;
}

export const FamilyTree: React.FC<FamilyTreeProps> = ({ results, deceasedGender, language }) => {
  const nodeWidth = 175;
  const nodeHeight = 105;
  const t = i18nStrings[language] || i18nStrings.en;

  const positions: Record<string, { x: number; y: number }> = {
    grandfather: { x: 150, y: 80 },
    paternalGrandmother: { x: 350, y: 80 },
    maternalGrandmother: { x: 750, y: 80 },

    father: { x: 250, y: 220 },
    mother: { x: 650, y: 220 },

    deceased: { x: 450, y: 400 },
    husband: { x: 750, y: 400 },
    wife: { x: 750, y: 400 },

    fullBrother: { x: 100, y: 300 },
    fullSister: { x: 100, y: 500 },
    paternalBrother: { x: 250, y: 360 },
    paternalSister: { x: 250, y: 460 },
    maternalBrother: { x: 650, y: 360 },
    maternalSister: { x: 650, y: 460 },

    son: { x: 300, y: 620 },
    daughter: { x: 600, y: 620 },

    grandson: { x: 300, y: 780 },
    granddaughter: { x: 600, y: 780 },

    nephewFull: { x: 880, y: 580 },
    nephewPaternal: { x: 880, y: 680 },
    uncleFull: { x: 920, y: 150 },
    unclePaternal: { x: 920, y: 250 },
    cousinFull: { x: 920, y: 800 },
    cousinPaternal: { x: 920, y: 900 },

    governmentTreasury: { x: 525, y: 880 }
  };

  const activeResults = results.filter(r => r.count > 0 || r.isBlocked || r.heirId === 'governmentTreasury');

  const sortedHeirs = [...activeResults].sort((a, b) => {
    if (a.isBlocked && !b.isBlocked) return -1;
    if (!a.isBlocked && b.isBlocked) return 1;
    return 0;
  });

  const renderNode = (heir: CalculationResult | { id: 'deceased', label: string }) => {
    const isDeceased = 'id' in heir;
    const id = isDeceased ? 'deceased' : (heir as CalculationResult).heirId;
    const pos = positions[id];
    if (!pos) return null;

    const x = pos.x - nodeWidth / 2;
    const y = pos.y - nodeHeight / 2;

    const isBlocked = !isDeceased && (heir as CalculationResult).isBlocked;
    const count = !isDeceased ? (heir as CalculationResult).count : 1;
    const label = isDeceased ? (heir as any).label : (heir as CalculationResult).heirName;
    const totalShare = !isDeceased && !isBlocked ? `${(heir as CalculationResult).sharePercentage.toFixed(1)}%` : null;

    let bgColor = isDeceased ? '#1e293b' : isBlocked ? '#fef2f2' : '#f0fdf4';
    let borderColor = isDeceased ? '#0f172a' : isBlocked ? '#ef4444' : '#22c55e';
    let textColor = isDeceased ? '#ffffff' : isBlocked ? '#991b1b' : '#166534';

    if (id === 'governmentTreasury') {
      bgColor = '#fff7ed';
      borderColor = '#ea580c';
      textColor = '#9a3412';
    }

    return (
      <g key={id} className="transition-all duration-300 pointer-events-none">
        <rect
          x={x}
          y={y}
          width={nodeWidth}
          height={nodeHeight}
          rx="32"
          fill={bgColor}
          stroke={borderColor}
          strokeWidth="4"
          className="drop-shadow-lg"
        />
        <text
          x={pos.x}
          y={pos.y - (totalShare ? 20 : 0)}
          textAnchor="middle"
          dominantBaseline="middle"
          fill={textColor}
          className="text-[10px] font-black uppercase tracking-wider font-arabic"
        >
          {label}
        </text>
        {!isDeceased && count > 1 && (
           <text
            x={pos.x}
            y={pos.y + 10}
            textAnchor="middle"
            dominantBaseline="middle"
            fill={textColor}
            className="text-[9px] font-black uppercase opacity-60 tracking-widest"
          >
            {t.table.count}: {count}
          </text>
        )}
        {totalShare && (
          <text
            x={pos.x}
            y={pos.y + 26}
            textAnchor="middle"
            dominantBaseline="middle"
            fill={textColor}
            className="text-[16px] font-black"
          >
            {totalShare}
          </text>
        )}
        {isBlocked && (
          <text
            x={pos.x}
            y={pos.y + 30}
            textAnchor="middle"
            dominantBaseline="middle"
            fill="#ef4444"
            className="text-[10px] font-black uppercase tracking-widest"
          >
            {t.heirTypes.Blocked}
          </text>
        )}
      </g>
    );
  };

  const renderConnection = (fromId: string, toId: string) => {
    const from = positions[fromId];
    const to = positions[toId];
    if (!from || !to) return null;

    return (
      <path
        key={`${fromId}-${toId}`}
        d={`M ${from.x} ${from.y} L ${to.x} ${to.y}`}
        stroke="#e2e8f0"
        strokeWidth="2"
        fill="none"
        strokeDasharray="8 6"
        className="opacity-40"
      />
    );
  };

  const deceasedStatusLabel = `${t.deceasedLabel} (${deceasedGender === DeceasedGender.Male ? t.male : t.female})`;

  return (
    <div className="w-full overflow-x-auto bg-white rounded-[2.5rem] border border-slate-100 p-4 md:p-12 shadow-inner print:p-0">
      <svg viewBox="0 0 1050 950" className="min-w-[1000px] h-auto print:w-full">
        {sortedHeirs.map(r => renderConnection('deceased', r.heirId))}
        {sortedHeirs.filter(r => r.isBlocked).map(r => renderNode(r))}
        {renderNode({ id: 'deceased', label: deceasedStatusLabel })}
        {sortedHeirs.filter(r => !r.isBlocked).map(r => renderNode(r))}
      </svg>
    </div>
  );
};

import { HeirKey, CalculationResult, DeceasedGender, InheritanceState, FiqhSchool } from '../types';
import { ALL_HEIRS, i18nStrings } from '../constants';

export const calculateInheritance = (state: InheritanceState): CalculationResult[] => {
  const { 
    totalEstate, 
    funeralExpenses, 
    debts, 
    wasiyyat, 
    deceasedGender, 
    heirs, 
    school,
    language
  } = state;

  const t = i18nStrings[language] || i18nStrings.en;
  let results: CalculationResult[] = [];

  const deductions = (funeralExpenses || 0) + (debts || 0) + (wasiyyat || 0);
  const netEstate = Math.max(0, totalEstate - deductions);

  // Clean heirs based on gender logic
  const activeHeirs = { ...heirs };
  if (deceasedGender === DeceasedGender.Male) activeHeirs.husband = 0;
  if (deceasedGender === DeceasedGender.Female) activeHeirs.wife = 0;

  // Key relationships for Hajb
  const nSon = activeHeirs.son || 0;
  const nGrandson = activeHeirs.grandson || 0;
  const nFather = activeHeirs.father || 0;
  const nGrandfather = activeHeirs.grandfather || 0;
  const nMother = activeHeirs.mother || 0;

  const hasMaleDescendant = nSon > 0 || nGrandson > 0;
  const hasDaughter = (activeHeirs.daughter || 0) > 0;
  const hasGranddaughter = (activeHeirs.granddaughter || 0) > 0;
  const hasDescendant = hasMaleDescendant || hasDaughter || hasGranddaughter;

  const sibCount = (activeHeirs.fullBrother || 0) + (activeHeirs.fullSister || 0) +
                   (activeHeirs.paternalBrother || 0) + (activeHeirs.paternalSister || 0) +
                   (activeHeirs.maternalBrother || 0) + (activeHeirs.maternalSister || 0);

  const blocked: Partial<Record<HeirKey, string>> = {};

  // --- HAJB HIRMAN (TOTAL EXCLUSION) RULES ---

  // 1. Son Exclusions
  if (nSon > 0) {
    const sonLabel = t.heirs.son;
    blocked.grandson = sonLabel;
    blocked.granddaughter = sonLabel;
    blocked.fullBrother = sonLabel;
    blocked.fullSister = sonLabel;
    blocked.paternalBrother = sonLabel;
    blocked.paternalSister = sonLabel;
    blocked.maternalBrother = sonLabel;
    blocked.maternalSister = sonLabel;
    blocked.nephewFull = sonLabel;
    blocked.nephewPaternal = sonLabel;
    blocked.uncleFull = sonLabel;
    blocked.unclePaternal = sonLabel;
    blocked.cousinFull = sonLabel;
    blocked.cousinPaternal = sonLabel;
  }

  // 2. Grandson Exclusions (blocked by Son, blocks those below)
  if (nGrandson > 0 && !blocked.grandson) {
    const gsLabel = t.heirs.grandson;
    blocked.fullBrother = gsLabel;
    blocked.fullSister = gsLabel;
    blocked.paternalBrother = gsLabel;
    blocked.paternalSister = gsLabel;
    blocked.maternalBrother = gsLabel;
    blocked.maternalSister = gsLabel;
    blocked.nephewFull = gsLabel;
    blocked.nephewPaternal = gsLabel;
    // Note: Grandson also blocks uncles/cousins in all schools
    blocked.uncleFull = gsLabel;
    blocked.unclePaternal = gsLabel;
    blocked.cousinFull = gsLabel;
    blocked.cousinPaternal = gsLabel;
  }

  // 3. Father Exclusions
  if (nFather > 0) {
    const fLabel = t.heirs.father;
    blocked.grandfather = fLabel;
    blocked.paternalGrandmother = fLabel;
    blocked.fullBrother = fLabel;
    blocked.fullSister = fLabel;
    blocked.paternalBrother = fLabel;
    blocked.paternalSister = fLabel;
    blocked.maternalBrother = fLabel;
    blocked.maternalSister = fLabel;
    blocked.nephewFull = fLabel;
    blocked.nephewPaternal = fLabel;
    blocked.uncleFull = fLabel;
    blocked.unclePaternal = fLabel;
    blocked.cousinFull = fLabel;
    blocked.cousinPaternal = fLabel;
  }

  // 4. Grandfather Exclusions
  if (nGrandfather > 0 && !blocked.grandfather) {
    const gfLabel = t.heirs.grandfather;
    blocked.maternalBrother = gfLabel;
    blocked.maternalSister = gfLabel;

    // Hanafi School Difference: Grandfather blocks all siblings
    if (school === FiqhSchool.Hanafi) {
      blocked.fullBrother = gfLabel;
      blocked.fullSister = gfLabel;
      blocked.paternalBrother = gfLabel;
      blocked.paternalSister = gfLabel;
    }

    // Grandfather always blocks nephews/uncles/cousins
    blocked.nephewFull = gfLabel;
    blocked.nephewPaternal = gfLabel;
    blocked.uncleFull = gfLabel;
    blocked.unclePaternal = gfLabel;
    blocked.cousinFull = gfLabel;
    blocked.cousinPaternal = gfLabel;
  }

  // 5. Mother Exclusions
  if (nMother > 0) {
    const mLabel = t.heirs.mother;
    blocked.paternalGrandmother = mLabel;
    blocked.maternalGrandmother = mLabel;
  }

  // 6. Full Brother Exclusions
  if ((activeHeirs.fullBrother || 0) > 0 && !blocked.fullBrother) {
    const fbLabel = t.heirs.fullBrother;
    blocked.paternalBrother = fbLabel;
    blocked.paternalSister = fbLabel;
    blocked.nephewFull = fbLabel;
    blocked.nephewPaternal = fbLabel;
    blocked.uncleFull = fbLabel;
    blocked.unclePaternal = fbLabel;
    blocked.cousinFull = fbLabel;
    blocked.cousinPaternal = fbLabel;
  }

  // 7. Full Sister Special (becomes Residuary with Daughter)
  const fullSisterAsResiduary = !blocked.fullSister && (activeHeirs.fullSister || 0) > 0 && hasDaughter && !hasMaleDescendant && !nFather && !nSon;
  if (fullSisterAsResiduary) {
     const fsLabel = t.heirs.fullSister;
     blocked.paternalBrother = fsLabel;
     blocked.paternalSister = fsLabel;
     blocked.nephewFull = fsLabel;
     blocked.nephewPaternal = fsLabel;
  }

  // --- SHARE CALCULATION ---
  let shares: Partial<Record<HeirKey, number>> = {};
  const categoryMap: Partial<Record<HeirKey, 'Sharer' | 'Residuary' | 'Treasury'>> = {};
  let totalFurud = 0;

  // Spouses
  if (activeHeirs.husband > 0) {
    shares.husband = hasDescendant ? 1/4 : 1/2;
    categoryMap.husband = 'Sharer';
    totalFurud += shares.husband;
  }
  if (activeHeirs.wife > 0) {
    shares.wife = hasDescendant ? 1/8 : 1/4;
    categoryMap.wife = 'Sharer';
    totalFurud += shares.wife;
  }

  // Parents
  if (nFather > 0 && !blocked.father) {
    if (hasMaleDescendant) {
      shares.father = 1/6;
      categoryMap.father = 'Sharer';
      totalFurud += 1/6;
    } else {
      // Residuary if no male descendant
      categoryMap.father = 'Residuary';
    }
  }
  if (nMother > 0 && !blocked.mother) {
    shares.mother = (hasDescendant || sibCount >= 2) ? 1/6 : 1/3;
    categoryMap.mother = 'Sharer';
    totalFurud += shares.mother;
  }

  // Daughters
  if (hasDaughter && !hasSon && !blocked.daughter) {
    shares.daughter = activeHeirs.daughter === 1 ? 1/2 : 2/3;
    categoryMap.daughter = 'Sharer';
    totalFurud += shares.daughter;
  }

  // Awal Logic (if total shares > 1)
  if (totalFurud > 1) {
    const factor = totalFurud;
    Object.keys(shares).forEach(k => { shares[k as HeirKey]! /= factor; });
    totalFurud = 1;
  }

  // Residue Calculation
  let residue = 1 - totalFurud;
  if (residue > 1e-6) {
    const asabaList: HeirKey[] = [];
    if (nSon > 0) {
      asabaList.push('son');
      if (hasDaughter) asabaList.push('daughter');
    } else if (nGrandson > 0 && !blocked.grandson) {
      asabaList.push('grandson');
      if (hasGranddaughter) asabaList.push('granddaughter');
    } else if (nFather > 0 && !blocked.father && !hasMaleDescendant) {
      asabaList.push('father');
    } else if (nGrandfather > 0 && !blocked.grandfather && !hasMaleDescendant) {
      asabaList.push('grandfather');
    } else if ((activeHeirs.fullBrother || 0) > 0 && !blocked.fullBrother) {
      asabaList.push('fullBrother');
      if ((activeHeirs.fullSister || 0) > 0) asabaList.push('fullSister');
    }

    if (asabaList.length > 0) {
      let totalWeight = 0;
      asabaList.forEach(k => {
        const weight = ALL_HEIRS.find(h => h.id === k)?.gender === 'M' ? 2 : 1;
        totalWeight += weight * (activeHeirs[k] || 1);
      });
      asabaList.forEach(k => {
        const weight = ALL_HEIRS.find(h => h.id === k)?.gender === 'M' ? 2 : 1;
        const s = (residue * weight * (activeHeirs[k] || 1)) / totalWeight;
        shares[k] = (shares[k] || 0) + s;
        categoryMap[k] = 'Residuary';
      });
      residue = 0;
    }
  }

  // Build Results
  ALL_HEIRS.forEach(def => {
    const count = activeHeirs[def.id] || 0;
    const isHeirBlocked = !!blocked[def.id];

    if (count > 0 || isHeirBlocked) {
      const share = shares[def.id] || 0;
      results.push({
        heirId: def.id,
        heirName: t.heirs[def.id],
        count,
        shareFraction: formatFraction(share),
        sharePercentage: share * 100,
        shareAmount: share * netEstate,
        shareAmountPerHeir: count > 0 ? (share * netEstate) / count : 0,
        sharePercentagePerHeir: count > 0 ? (share * 100) / count : 0,
        isBlocked: isHeirBlocked,
        blockedBy: blocked[def.id],
        explanation: getDetailedExplanation(def.id, isHeirBlocked, share > 0, categoryMap[def.id], hasDescendant, activeHeirs[def.id], t),
        quranReference: getQuranRef(def.id),
        heirType: isHeirBlocked ? 'Blocked' : (categoryMap[def.id] as any || 'Sharer')
      });
    }
  });

  // Handle remaining residue (Radd or Treasury)
  const totalDistributed = results.reduce((sum, r) => sum + r.sharePercentage, 0);
  if (totalDistributed < 99.9 && netEstate > 0) {
    const remainingRatio = (100 - totalDistributed) / 100;
    results.push({
      heirId: 'governmentTreasury',
      heirName: t.heirs.governmentTreasury,
      count: 1,
      shareFraction: formatFraction(remainingRatio),
      sharePercentage: remainingRatio * 100,
      shareAmount: remainingRatio * netEstate,
      shareAmountPerHeir: remainingRatio * netEstate,
      sharePercentagePerHeir: remainingRatio * 100,
      isBlocked: false,
      explanation: t.exp_treasury,
      heirType: 'Treasury'
    });
  }

  return results;
};

const formatFraction = (val: number): string => {
  if (val < 1e-6) return '0';
  const denominators = [2, 3, 4, 6, 8, 12, 13, 15, 17, 24, 27, 32, 48];
  for (const d of denominators) {
    const n = Math.round(val * d);
    if (Math.abs(val - n / d) < 1e-3) return `${n}/${d}`;
  }
  return val.toFixed(3);
};

const getDetailedExplanation = (id: HeirKey, isBlocked: boolean, hasShare: boolean, type: string | undefined, hasDesc: boolean, count: number, t: any): string => {
  if (isBlocked) return t.exp_blocked;
  if (!hasShare) return t.exp_no_share;

  switch (id) {
    case 'husband': return hasDesc ? t.exp_husband_2 : t.exp_husband_1;
    case 'wife': return hasDesc ? t.exp_wife_2 : t.exp_wife_1;
    case 'son': return t.exp_son;
    case 'daughter':
      if (type === 'Residuary') return t.exp_daughter_3;
      return count === 1 ? t.exp_daughter_1 : t.exp_daughter_2;
    case 'father': return type === 'Sharer' ? t.exp_father_1 : t.exp_father_2;
    case 'mother': return hasDesc || count > 1 ? t.exp_mother_1 : t.exp_mother_2;
    default: return t.exp_general;
  }
};

const getQuranRef = (id: HeirKey): string => {
  const refs: Partial<Record<HeirKey, string>> = {
    son: '4:11', daughter: '4:11', father: '4:11', mother: '4:11',
    husband: '4:12', wife: '4:12', maternalBrother: '4:12', maternalSister: '4:12',
    fullSister: '4:176', paternalSister: '4:176'
  };
  return refs[id] || '';
};

import React, { useState, useMemo } from 'react';
import { 
  InheritanceState, 
  DeceasedGender, 
  FiqhSchool, 
  HeirKey 
} from './types';
import { 
  CURRENCIES, 
  LANGUAGES, 
  MALE_HEIRS, 
  FEMALE_HEIRS, 
  i18nStrings 
} from './constants';
import { calculateInheritance } from './logic/calculator';
import { FamilyTree } from './FamilyTree';
import { ResultExplanations } from './ResultExplanations';
import { 
  Calculator, Users, Globe, Landmark, 
  ArrowRight, RotateCcw, 
  Info, Network, Coins, MinusCircle, AlertTriangle, X, FileText, Download, ShieldCheck
} from 'lucide-react';

const HEIR_LIMITS: Record<string, number> = {
  husband: 1,
  wife: 4,
  father: 1,
  mother: 1,
  grandfather: 1,
  paternalGrandmother: 1,
  maternalGrandmother: 1
};

const DEFAULT_MAX_LIMIT = 100;

const App: React.FC = () => {
  const [state, setState] = useState<InheritanceState>({
    totalEstate: 0, 
    funeralExpenses: 0,
    debts: 0,
    wasiyyat: 0,
    currency: 'USD',
    deceasedGender: DeceasedGender.Male,
    school: FiqhSchool.Hanafi,
    language: 'en',
    heirs: {} as Record<HeirKey, number>
  });

  const [isCalculated, setIsCalculated] = useState(false);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);

  const t = i18nStrings[state.language] || i18nStrings.en;

  const sortedLanguages = useMemo(() => {
    return [...LANGUAGES].sort((a, b) => {
      if (a.code === state.language) return -1;
      if (b.code === state.language) return 1;
      return 0;
    });
  }, [state.language]);

  const formattedCurrencies = useMemo(() => {
    return [...CURRENCIES].map(c => {
      const localizedName = t.currencies[c.code] || c.nameEn;
      const displayLabel = state.language === 'en' 
        ? `${c.nameEn} (${c.symbol})`
        : `${localizedName} / ${c.nameEn} (${c.symbol})`;
      return { ...c, displayLabel };
    }).sort((a, b) => {
       if (a.code === state.currency) return -1;
       if (b.code === state.currency) return 1;
       return 0;
    });
  }, [state.currency, state.language, t.currencies]);

  const results = useMemo(() => {
    return calculateInheritance(state);
  }, [state]);

  const blockedHeirIds = useMemo(() => {
    return new Set(results.filter(r => r.isBlocked).map(r => r.heirId));
  }, [results]);

  const triggerError = (msg: string) => {
    setErrorMessage(msg);
    setTimeout(() => setErrorMessage(null), 5000);
  };

  const resetAll = () => {
    setState({
      totalEstate: 0,
      funeralExpenses: 0,
      debts: 0,
      wasiyyat: 0,
      currency: state.currency,
      deceasedGender: state.deceasedGender,
      school: state.school,
      language: state.language,
      heirs: {} as Record<HeirKey, number>
    });
    setIsCalculated(false);
    setErrorMessage(null);
  };

  const handleHeirChange = (key: HeirKey, value: number) => {
    const max = HEIR_LIMITS[key] || DEFAULT_MAX_LIMIT;
    if (value > max) {
      triggerError(`Maximum limit for ${t.heirs?.[key] || key} is ${max}.`);
      return;
    }
    const val = Math.max(0, value);
    setState(prev => ({
      ...prev,
      heirs: { ...prev.heirs, [key]: val }
    }));
    setIsCalculated(false);
  };

  const handleNumericInput = (field: keyof InheritanceState, value: number) => {
    if (value < 0) return;
    if (field === 'totalEstate' && (value === 0 || isNaN(value))) {
      resetAll();
      return;
    }
    setState(prev => ({ ...prev, [field]: value }));
    setIsCalculated(false);
  };

  const handleExportPDF = () => {
    window.print();
  };

  const renderHeirInput = (h: any) => {
    // Hide invalid spouses based on deceased gender
    if (h.id === 'husband' && state.deceasedGender === DeceasedGender.Male) return null;
    if (h.id === 'wife' && state.deceasedGender === DeceasedGender.Female) return null;

    const count = state.heirs[h.id] || 0;
    const isFilled = count > 0;
    const isBlocked = blockedHeirIds.has(h.id);
    const blocker = results.find(r => r.heirId === h.id)?.blockedBy;

    let containerClass = "p-4 md:p-5 rounded-[2rem] border-4 transition-all group relative overflow-hidden ";
    let labelClass = "block text-[10px] font-black uppercase mb-2 md:mb-3 leading-tight ";
    let inputClass = "w-full border-none rounded-xl text-lg md:text-2xl font-black py-2 md:py-3 px-3 md:px-5 outline-none transition-all shadow-inner ";

    if (isBlocked) {
      containerClass += "bg-red-50 border-red-500 shadow-lg shadow-red-100 scale-[0.98]";
      labelClass += "text-red-700";
      inputClass += "bg-white text-red-800 focus:ring-2 focus:ring-red-500 opacity-50 cursor-not-allowed";
    } else if (isFilled) {
      containerClass += "bg-green-50 border-green-500 shadow-lg shadow-green-100";
      labelClass += "text-green-700";
      inputClass += "bg-white text-green-700";
    } else {
      containerClass += "bg-slate-50 border-slate-50 hover:border-orange-200";
      labelClass += "text-slate-500";
      inputClass += "bg-white text-slate-800 focus:ring-2 focus:ring-orange-500";
    }

    const translatedName = t.heirs?.[h.id] || h.nameEn;
    const limitDisplay = HEIR_LIMITS[h.id] ? `(0-${HEIR_LIMITS[h.id]})` : `(0-100)`;

    return (
      <div key={h.id} className={containerClass}>
        <label className={labelClass}>
          {translatedName} {limitDisplay}
          {isBlocked && blocker && <span className="block text-[8px] mt-1 font-black">({t.blockedBy} {blocker})</span>}
        </label>
        <input 
          type="number" 
          min="0" 
          value={count || ''}
          placeholder="0"
          disabled={isBlocked}
          onChange={(e) => handleHeirChange(h.id, Number(e.target.value))}
          className={inputClass}
        />
      </div>
    );
  };

  const renderDeductionInput = (label: string, value: number, field: 'funeralExpenses' | 'debts' | 'wasiyyat') => {
    const isFilled = value > 0;
    return (
      <div className="flex-1">
        <label className="block text-[10px] font-black uppercase text-slate-400 mb-2 tracking-widest leading-relaxed">
          {label}
        </label>
        <div className="relative">
          <input 
            type="number" 
            value={value || ''} 
            placeholder="0"
            onChange={(e) => handleNumericInput(field, Number(e.target.value))}
            className={`w-full border-4 rounded-[1.5rem] py-3 md:py-4 px-4 md:px-6 font-black text-lg md:text-xl outline-none transition-all placeholder-slate-300 shadow-inner ${isFilled ? 'bg-green-50 border-green-500 text-green-700' : 'bg-slate-50 border-slate-100 focus:border-red-500'}`}
          />
          <div className={`absolute right-4 top-1/2 -translate-y-1/2 font-black text-sm opacity-60 pointer-events-none ${isFilled ? 'text-emerald-500' : 'text-slate-400'}`}>
            {CURRENCIES.find(c => c.code === state.currency)?.symbol || '$'}
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen pb-20 px-4 md:px-8 bg-slate-50 text-slate-900 font-black">
      {errorMessage && (
        <div className="fixed top-8 left-1/2 -translate-x-1/2 z-[9999] animate-in slide-in-from-top-4 duration-300 w-full max-w-md px-4">
          <div className="bg-red-600 text-white p-5 rounded-[2rem] shadow-2xl flex items-center justify-between gap-4 border-4 border-red-400">
            <div className="flex items-center gap-3">
              <AlertTriangle className="shrink-0" />
              <p className="font-black text-sm md:text-base leading-tight">{errorMessage}</p>
            </div>
            <button onClick={() => setErrorMessage(null)} className="hover:bg-red-700 p-2 rounded-full transition-colors">
              <X size={20} />
            </button>
          </div>
        </div>
      )}

      <header className="max-w-7xl mx-auto py-8 flex flex-col md:flex-row justify-between items-center gap-6 no-print">
        <div className="flex items-center gap-4">
          <div className="bg-orange-600 p-4 rounded-3xl shadow-xl transition-transform hover:scale-105 active:scale-95 cursor-pointer">
            <Landmark className="text-white w-9 h-9" />
          </div>
          <div>
            <h1 className="text-4xl font-black tracking-tighter font-arabic leading-none">{t.title}</h1>
            <p className="text-orange-600 text-[10px] font-black uppercase tracking-[0.4em] mt-1.5">{t.subtitle}</p>
          </div>
        </div>

        <div className="grid grid-cols-2 md:flex items-center gap-3 w-full md:w-auto">
          <div className="flex items-center gap-2 bg-white p-3 rounded-2xl shadow-sm border border-slate-200">
            <Coins size={18} className="text-emerald-600 shrink-0" />
            <select 
              value={state.currency} 
              onChange={(e) => setState({...state, currency: e.target.value})}
              className="bg-transparent border-none text-[10px] md:text-sm font-black focus:ring-0 w-full cursor-pointer pr-4"
            >
              {formattedCurrencies.map(c => (
                <option key={c.code} value={c.code} className="font-sans">
                  {c.displayLabel}
                </option>
              ))}
            </select>
          </div>

          <div className="flex items-center gap-2 bg-white p-3 rounded-2xl shadow-sm border border-slate-200">
            <Globe size={18} className="text-blue-500 shrink-0" />
            <select 
              value={state.language} 
              onChange={(e) => setState({...state, language: e.target.value})}
              className="bg-transparent border-none text-[10px] md:text-sm font-black focus:ring-0 w-full cursor-pointer pr-4"
            >
              {sortedLanguages.map(l => <option key={l.code} value={l.code} className="font-sans">{l.name}</option>)}
            </select>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-8 md:gap-12">
        <div className="lg:col-span-5 space-y-8 no-print">
          <section className="bg-white p-6 md:p-10 rounded-[3rem] shadow-2xl shadow-slate-200/50 border border-slate-100">
            <h2 className="text-2xl font-black mb-8 flex items-center gap-4">
              <Calculator className="text-orange-600" size={28} />
              {t.summary}
            </h2>
            <div className="space-y-8">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-[10px] font-black uppercase text-slate-400 mb-2 tracking-widest">{t.distributionAmount}</label>
                  <div className="relative">
                    <input 
                      type="number" 
                      value={state.totalEstate || ''} 
                      placeholder="0"
                      onChange={(e) => handleNumericInput('totalEstate', Number(e.target.value))}
                      className={`w-full border-4 rounded-[2rem] py-4 md:py-6 px-4 md:px-8 font-black text-xl md:text-3xl outline-none transition-all placeholder-slate-300 shadow-inner ${state.totalEstate > 0 ? 'bg-green-50 border-green-500 text-green-700' : 'bg-slate-50 border-slate-100 focus:border-orange-500'}`}
                    />
                    <div className="absolute right-4 md:right-8 top-1/2 -translate-y-1/2 font-black text-sm md:text-2xl opacity-60 pointer-events-none text-slate-400">
                      {CURRENCIES.find(c => c.code === state.currency)?.symbol || '$'}
                    </div>
                  </div>
                </div>

                <div>
                  <label className="block text-[10px] font-black uppercase text-slate-400 mb-2 tracking-widest">{t.fiqhSchool}</label>
                  <select 
                    value={state.school} 
                    onChange={(e) => {
                      setState({...state, school: e.target.value as FiqhSchool});
                      setIsCalculated(false);
                    }}
                    className="w-full h-[60px] md:h-[92px] bg-slate-50 border-none rounded-[2rem] px-4 md:px-8 font-black text-xs md:text-lg focus:ring-4 focus:ring-orange-500 transition-all cursor-pointer"
                  >
                    {Object.values(FiqhSchool).map(s => <option key={s} value={s}>{t.schools[s] || s}</option>)}
                  </select>
                </div>
              </div>

              <div>
                <label className="block text-[10px] font-black uppercase text-slate-400 mb-3 tracking-widest">{t.deceasedGender}</label>
                <div className="flex p-2 bg-slate-100 rounded-[2.5rem] border-2 border-slate-200">
                  <button 
                    onClick={() => {
                      setState({...state, deceasedGender: DeceasedGender.Male, heirs: {} as any});
                      setIsCalculated(false);
                    }}
                    className={`flex-1 py-3 md:py-5 text-sm md:text-lg font-black rounded-[2rem] transition-all ${state.deceasedGender === DeceasedGender.Male ? 'bg-orange-600 shadow-xl text-white scale-[1.03]' : 'text-slate-400 hover:text-slate-600'}`}
                  >
                    {t.male}
                  </button>
                  <button 
                    onClick={() => {
                      setState({...state, deceasedGender: DeceasedGender.Female, heirs: {} as any});
                      setIsCalculated(false);
                    }}
                    className={`flex-1 py-3 md:py-5 text-sm md:text-lg font-black rounded-[2rem] transition-all ${state.deceasedGender === DeceasedGender.Female ? 'bg-orange-600 shadow-xl text-white scale-[1.03]' : 'text-slate-400 hover:text-slate-600'}`}
                  >
                    {t.female}
                  </button>
                </div>
              </div>
            </div>
          </section>

          <section className="bg-white p-6 md:p-10 rounded-[3rem] shadow-2xl shadow-slate-200/50 border border-slate-100">
            <h2 className="text-2xl font-black mb-8 flex items-center gap-4">
              <MinusCircle className="text-red-500" size={28} />
              {t.deductions}
            </h2>
            <div className="space-y-6">
              {renderDeductionInput(t.funeralExpenses, state.funeralExpenses, 'funeralExpenses')}
              {renderDeductionInput(t.debts, state.debts, 'debts')}
              {renderDeductionInput(t.wasiyyat, state.wasiyyat, 'wasiyyat')}
            </div>
          </section>

          <section className="bg-white p-6 md:p-10 rounded-[3rem] shadow-2xl shadow-slate-200/50 border border-slate-100">
            <h2 className="text-2xl font-black mb-10 flex items-center gap-4">
              <Users className="text-orange-600" size={28} />
              {t.heirsSelection}
            </h2>
            <div className="grid grid-cols-2 gap-4 md:gap-6">
              {/* Spouses filter */}
              {MALE_HEIRS.filter(h => h.id === 'husband').map(renderHeirInput)}
              {FEMALE_HEIRS.filter(h => h.id === 'wife').map(renderHeirInput)}

              {[...MALE_HEIRS, ...FEMALE_HEIRS]
                .filter(h => h.id !== 'husband' && h.id !== 'wife' && h.id !== 'freedSlaveMale' && h.id !== 'freedSlaveFemale')
                .map(renderHeirInput)}
            </div>
          </section>

          <div className="flex flex-col sm:flex-row gap-4 md:gap-6">
            <button 
              onClick={() => setIsCalculated(true)}
              className="flex-[2] bg-orange-600 hover:bg-orange-700 text-white font-black py-5 md:py-7 px-6 md:px-10 rounded-[2.5rem] shadow-2xl shadow-orange-500/30 transition-all flex items-center justify-center gap-3 group active:scale-95"
            >
              <span className="text-md md:text-xl">{t.calculate}</span>
              <ArrowRight size={28} className="group-hover:translate-x-3 transition-transform" />
            </button>
            <button 
              onClick={resetAll}
              className="flex-1 bg-slate-800 hover:bg-slate-900 text-white font-black py-5 md:py-7 px-6 md:px-10 rounded-[2.5rem] shadow-2xl shadow-slate-900/30 transition-all flex items-center justify-center gap-3 group active:scale-95"
            >
              <RotateCcw size={24} className="group-hover:rotate-180 transition-transform duration-500" />
              <span className="text-md md:text-lg">{t.reset}</span>
            </button>
          </div>
        </div>

        <div className="lg:col-span-7 space-y-10">
          {!isCalculated ? (
            <div className="bg-white border-8 border-dashed border-slate-200 rounded-[4rem] p-10 md:p-24 flex flex-col items-center text-center no-print">
              <div className="bg-orange-50 p-10 rounded-full mb-10 shadow-inner">
                <Info size={80} className="text-orange-200" />
              </div>
              <h3 className="text-3xl font-black text-slate-800 mb-4">{t.results}</h3>
              <p className="text-slate-400 max-w-sm text-lg font-bold leading-relaxed">{t.noHeirs}</p>
            </div>
          ) : (
            <div className="space-y-10 animate-in fade-in slide-in-from-bottom-10 duration-500 print-container">
              {/* PAGE 1: HEADER & SUMMARY */}
              <div className="bg-white p-6 md:p-10 rounded-[3.5rem] shadow-2xl border border-slate-100 overflow-hidden page-break-after">
                <div className="print-only mb-10 text-center border-b-4 border-orange-600 pb-8">
                  <h1 className="text-4xl font-black font-arabic">{t.title}</h1>
                  <p className="text-orange-600 text-xs font-black uppercase tracking-[0.4em] mt-2">{t.subtitle}</p>
                </div>

                <div className="flex justify-between items-center mb-10">
                  <h2 className="text-3xl font-black flex items-center gap-3">
                    <span className="w-2 h-8 bg-orange-600 rounded-full block"></span>
                    {t.results}
                  </h2>
                </div>

                <div className="space-y-8">
                  <div className="bg-gradient-to-br from-slate-900 to-slate-800 p-8 md:p-12 rounded-[3rem] shadow-2xl text-white flex flex-col md:flex-row justify-between items-center gap-6">
                    <div className="w-full md:w-auto">
                      <p className="text-[10px] font-black uppercase mb-2 tracking-widest opacity-80">{t.distributionAmount}</p>
                      <p className="text-5xl md:text-7xl font-black flex items-baseline gap-2">
                        {state.totalEstate.toLocaleString()}
                        <span className="text-2xl font-bold opacity-70">{state.currency}</span>
                      </p>
                      {(state.funeralExpenses > 0 || state.debts > 0 || state.wasiyyat > 0) && (
                        <div className="mt-6 space-y-1 bg-white/10 p-4 rounded-2xl">
                           <p className="text-xs font-bold opacity-80">{t.totalDeductionsLabel}: {(state.funeralExpenses + state.debts + state.wasiyyat).toLocaleString()} {state.currency}</p>
                           <p className="text-sm font-black text-emerald-400">{t.netEstateLabel}: {(state.totalEstate - (state.funeralExpenses + state.debts + state.wasiyyat)).toLocaleString()} {state.currency}</p>
                        </div>
                      )}
                    </div>
                    <div className="flex gap-4">
                      <div className="bg-white/10 p-6 rounded-3xl backdrop-blur-sm text-center min-w-[120px]">
                        <p className="text-[10px] font-black uppercase opacity-70 mb-1">{t.fiqhSchool}</p>
                        <p className="text-xl font-black">{t.schools[state.school] || state.school}</p>
                      </div>
                      <div className="bg-white/10 p-6 rounded-3xl backdrop-blur-sm text-center min-w-[120px]">
                        <p className="text-[10px] font-black uppercase opacity-70 mb-1">{t.deceasedGender}</p>
                        <p className="text-xl font-black">{state.deceasedGender === DeceasedGender.Male ? t.male : t.female}</p>
                      </div>
                    </div>
                  </div>
                </div>
              </div>

              {/* PAGE 2: FAMILY TREE */}
              <div className="bg-white p-6 md:p-10 rounded-[3.5rem] shadow-2xl border border-slate-100 page-break-before page-break-after">
                <h2 className="text-2xl font-black mb-10 flex items-center gap-4">
                  <Network className="text-blue-500" size={28} />
                  {t.familyTree}
                </h2>
                <FamilyTree results={results} deceasedGender={state.deceasedGender} currency={state.currency} language={state.language} />
              </div>

              {/* PAGE 3: SHARE TABLE & EXPLANATIONS */}
              <div className="page-break-before">
                <ResultExplanations results={results} t={t} />
              </div>

              {/* CTA & PDF EXPORT SECTION */}
              <div className="mt-12 space-y-8 no-print">
                <div className="bg-gradient-to-r from-emerald-600 to-teal-700 p-10 md:p-14 rounded-[4rem] text-white shadow-3xl flex flex-col items-center text-center group">
                  <div className="bg-white/20 p-6 rounded-full mb-8 backdrop-blur-md group-hover:scale-110 transition-transform">
                    <FileText size={64} className="text-white" />
                  </div>
                  <h3 className="text-3xl font-black mb-4">Download Formal Report</h3>
                  <p className="text-emerald-100 font-bold max-w-lg mb-10 leading-relaxed">
                    Generate a detailed PDF calculation report including the family tree and Fiqh justifications to share with your local Imam or Islamic scholar for official verification.
                  </p>
                  <button 
                    onClick={handleExportPDF}
                    className="bg-white text-emerald-700 hover:bg-emerald-50 font-black py-6 px-12 rounded-full shadow-2xl transition-all flex items-center gap-4 text-xl active:scale-95"
                  >
                    <Download size={28} />
                    Download Calculation (PDF)
                  </button>
                  <div className="mt-8 flex items-center gap-2 opacity-60 text-xs uppercase tracking-widest font-black">
                    <ShieldCheck size={16} />
                    Professionally Verified for Mirath Standards
                  </div>
                </div>

                <div className="p-8 border-4 border-dashed border-slate-200 rounded-[3rem] text-slate-400 text-center text-sm font-bold">
                  <p className="mb-4">Disclaimer: This calculator is a tool to assist in understanding Al-Farā’iḍ. For official legal or religious distribution, please consult a qualified Mufti or inheritance specialist.</p>
                  <div className="flex justify-center gap-8 text-[10px] uppercase tracking-widest font-black">
                    <a href="#" className="hover:text-orange-600 transition-colors">Privacy Policy</a>
                    <a href="#" className="hover:text-orange-600 transition-colors">Terms of Use</a>
                  </div>
                </div>
              </div>

              {/* PRINT ONLY: CERTIFICATION BLOCK */}
              <div className="print-only mt-20 pt-20 border-t-2 border-slate-200 page-break-before">
                <div className="flex justify-between gap-20">
                  <div className="flex-1 text-center">
                    <div className="h-32 border-b-2 border-slate-200 mb-4"></div>
                    <p className="text-xs font-black uppercase tracking-widest">Imam / Scholar Signature</p>
                  </div>
                  <div className="flex-1 text-center">
                    <div className="h-32 border-b-2 border-slate-200 mb-4"></div>
                    <p className="text-xs font-black uppercase tracking-widest">Date & Official Stamp</p>
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>
      </main>

      <footer className="max-w-7xl mx-auto mt-20 pt-12 border-t border-slate-200 text-center no-print pb-10">
        <p className="text-slate-400 text-sm font-black tracking-widest uppercase opacity-60">
          &copy; {new Date().getFullYear()} {t.title} • Al-Farā’iḍ Professional
        </p>
      </footer>
    </div>
  );
};

export default App;

import { HeirKey, CalculationResult, DeceasedGender, InheritanceState, FiqhSchool } from '../types';
import { ALL_HEIRS, i18nStrings } from '../constants';

export const calculateInheritance = (state: InheritanceState): CalculationResult[] => {
  const { 
    totalEstate, 
    funeralExpenses, 
    debts, 
    wasiyyat, 
    deceasedGender, 
    heirs, 
    school,
    language
  } = state;

  const t = i18nStrings[language] || i18nStrings.en;
  let results: CalculationResult[] = [];

  const deductions = (funeralExpenses || 0) + (debts || 0) + (wasiyyat || 0);
  const netEstate = Math.max(0, totalEstate - deductions);

  // Clean heirs based on gender logic
  const activeHeirs = { ...heirs };
  if (deceasedGender === DeceasedGender.Male) activeHeirs.husband = 0;
  if (deceasedGender === DeceasedGender.Female) activeHeirs.wife = 0;

  // Key relationships for Hajb
  const nSon = activeHeirs.son || 0;
  const nGrandson = activeHeirs.grandson || 0;
  const nFather = activeHeirs.father || 0;
  const nGrandfather = activeHeirs.grandfather || 0;
  const nMother = activeHeirs.mother || 0;

  const hasMaleDescendant = nSon > 0 || nGrandson > 0;
  const hasDaughter = (activeHeirs.daughter || 0) > 0;
  const hasGranddaughter = (activeHeirs.granddaughter || 0) > 0;
  const hasDescendant = hasMaleDescendant || hasDaughter || hasGranddaughter;

  const sibCount = (activeHeirs.fullBrother || 0) + (activeHeirs.fullSister || 0) +
                   (activeHeirs.paternalBrother || 0) + (activeHeirs.paternalSister || 0) +
                   (activeHeirs.maternalBrother || 0) + (activeHeirs.maternalSister || 0);

  const blocked: Partial<Record<HeirKey, string>> = {};

  // --- HAJB HIRMAN (TOTAL EXCLUSION) RULES ---

  // 1. Son Exclusions
  if (nSon > 0) {
    const sonLabel = t.heirs.son;
    blocked.grandson = sonLabel;
    blocked.granddaughter = sonLabel;
    blocked.fullBrother = sonLabel;
    blocked.fullSister = sonLabel;
    blocked.paternalBrother = sonLabel;
    blocked.paternalSister = sonLabel;
    blocked.maternalBrother = sonLabel;
    blocked.maternalSister = sonLabel;
    blocked.nephewFull = sonLabel;
    blocked.nephewPaternal = sonLabel;
    blocked.uncleFull = sonLabel;
    blocked.unclePaternal = sonLabel;
    blocked.cousinFull = sonLabel;
    blocked.cousinPaternal = sonLabel;
  }

  // 2. Grandson Exclusions (blocked by Son, blocks those below)
  if (nGrandson > 0 && !blocked.grandson) {
    const gsLabel = t.heirs.grandson;
    blocked.fullBrother = gsLabel;
    blocked.fullSister = gsLabel;
    blocked.paternalBrother = gsLabel;
    blocked.paternalSister = gsLabel;
    blocked.maternalBrother = gsLabel;
    blocked.maternalSister = gsLabel;
    blocked.nephewFull = gsLabel;
    blocked.nephewPaternal = gsLabel;
    // Note: Grandson also blocks uncles/cousins in all schools
    blocked.uncleFull = gsLabel;
    blocked.unclePaternal = gsLabel;
    blocked.cousinFull = gsLabel;
    blocked.cousinPaternal = gsLabel;
  }

  // 3. Father Exclusions
  if (nFather > 0) {
    const fLabel = t.heirs.father;
    blocked.grandfather = fLabel;
    blocked.paternalGrandmother = fLabel;
    blocked.fullBrother = fLabel;
    blocked.fullSister = fLabel;
    blocked.paternalBrother = fLabel;
    blocked.paternalSister = fLabel;
    blocked.maternalBrother = fLabel;
    blocked.maternalSister = fLabel;
    blocked.nephewFull = fLabel;
    blocked.nephewPaternal = fLabel;
    blocked.uncleFull = fLabel;
    blocked.unclePaternal = fLabel;
    blocked.cousinFull = fLabel;
    blocked.cousinPaternal = fLabel;
  }

  // 4. Grandfather Exclusions
  if (nGrandfather > 0 && !blocked.grandfather) {
    const gfLabel = t.heirs.grandfather;
    blocked.maternalBrother = gfLabel;
    blocked.maternalSister = gfLabel;

    // Hanafi School Difference: Grandfather blocks all siblings
    if (school === FiqhSchool.Hanafi) {
      blocked.fullBrother = gfLabel;
      blocked.fullSister = gfLabel;
      blocked.paternalBrother = gfLabel;
      blocked.paternalSister = gfLabel;
    }

    // Grandfather always blocks nephews/uncles/cousins
    blocked.nephewFull = gfLabel;
    blocked.nephewPaternal = gfLabel;
    blocked.uncleFull = gfLabel;
    blocked.unclePaternal = gfLabel;
    blocked.cousinFull = gfLabel;
    blocked.cousinPaternal = gfLabel;
  }

  // 5. Mother Exclusions
  if (nMother > 0) {
    const mLabel = t.heirs.mother;
    blocked.paternalGrandmother = mLabel;
    blocked.maternalGrandmother = mLabel;
  }

  // 6. Full Brother Exclusions
  if ((activeHeirs.fullBrother || 0) > 0 && !blocked.fullBrother) {
    const fbLabel = t.heirs.fullBrother;
    blocked.paternalBrother = fbLabel;
    blocked.paternalSister = fbLabel;
    blocked.nephewFull = fbLabel;
    blocked.nephewPaternal = fbLabel;
    blocked.uncleFull = fbLabel;
    blocked.unclePaternal = fbLabel;
    blocked.cousinFull = fbLabel;
    blocked.cousinPaternal = fbLabel;
  }

  // 7. Full Sister Special (becomes Residuary with Daughter)
  const fullSisterAsResiduary = !blocked.fullSister && (activeHeirs.fullSister || 0) > 0 && hasDaughter && !hasMaleDescendant && !nFather && !nSon;
  if (fullSisterAsResiduary) {
     const fsLabel = t.heirs.fullSister;
     blocked.paternalBrother = fsLabel;
     blocked.paternalSister = fsLabel;
     blocked.nephewFull = fsLabel;
     blocked.nephewPaternal = fsLabel;
  }

  // --- SHARE CALCULATION ---
  let shares: Partial<Record<HeirKey, number>> = {};
  const categoryMap: Partial<Record<HeirKey, 'Sharer' | 'Residuary' | 'Treasury'>> = {};
  let totalFurud = 0;

  // Spouses
  if (activeHeirs.husband > 0) {
    shares.husband = hasDescendant ? 1/4 : 1/2;
    categoryMap.husband = 'Sharer';
    totalFurud += shares.husband;
  }
  if (activeHeirs.wife > 0) {
    shares.wife = hasDescendant ? 1/8 : 1/4;
    categoryMap.wife = 'Sharer';
    totalFurud += shares.wife;
  }

  // Parents
  if (nFather > 0 && !blocked.father) {
    if (hasMaleDescendant) {
      shares.father = 1/6;
      categoryMap.father = 'Sharer';
      totalFurud += 1/6;
    } else {
      // Residuary if no male descendant
      categoryMap.father = 'Residuary';
    }
  }
  if (nMother > 0 && !blocked.mother) {
    shares.mother = (hasDescendant || sibCount >= 2) ? 1/6 : 1/3;
    categoryMap.mother = 'Sharer';
    totalFurud += shares.mother;
  }

  // Daughters
  // Fix: Replaced undefined variable 'hasSon' with 'nSon === 0' to correctly check for the absence of sons.
  if (hasDaughter && nSon === 0 && !blocked.daughter) {
    shares.daughter = activeHeirs.daughter === 1 ? 1/2 : 2/3;
    categoryMap.daughter = 'Sharer';
    totalFurud += shares.daughter;
  }

  // Awal Logic (if total shares > 1)
  if (totalFurud > 1) {
    const factor = totalFurud;
    Object.keys(shares).forEach(k => { shares[k as HeirKey]! /= factor; });
    totalFurud = 1;
  }

  // Residue Calculation
  let residue = 1 - totalFurud;
  if (residue > 1e-6) {
    const asabaList: HeirKey[] = [];
    if (nSon > 0) {
      asabaList.push('son');
      if (hasDaughter) asabaList.push('daughter');
    } else if (nGrandson > 0 && !blocked.grandson) {
      asabaList.push('grandson');
      if (hasGranddaughter) asabaList.push('granddaughter');
    } else if (nFather > 0 && !blocked.father && !hasMaleDescendant) {
      asabaList.push('father');
    } else if (nGrandfather > 0 && !blocked.grandfather && !hasMaleDescendant) {
      asabaList.push('grandfather');
    } else if ((activeHeirs.fullBrother || 0) > 0 && !blocked.fullBrother) {
      asabaList.push('fullBrother');
      if ((activeHeirs.fullSister || 0) > 0) asabaList.push('fullSister');
    }

    if (asabaList.length > 0) {
      let totalWeight = 0;
      asabaList.forEach(k => {
        const weight = ALL_HEIRS.find(h => h.id === k)?.gender === 'M' ? 2 : 1;
        totalWeight += weight * (activeHeirs[k] || 1);
      });
      asabaList.forEach(k => {
        const weight = ALL_HEIRS.find(h => h.id === k)?.gender === 'M' ? 2 : 1;
        const s = (residue * weight * (activeHeirs[k] || 1)) / totalWeight;
        shares[k] = (shares[k] || 0) + s;
        categoryMap[k] = 'Residuary';
      });
      residue = 0;
    }
  }

  // Build Results
  ALL_HEIRS.forEach(def => {
    const count = activeHeirs[def.id] || 0;
    const isHeirBlocked = !!blocked[def.id];

    if (count > 0 || isHeirBlocked) {
      const share = shares[def.id] || 0;
      results.push({
        heirId: def.id,
        heirName: t.heirs[def.id],
        count,
        shareFraction: formatFraction(share),
        sharePercentage: share * 100,
        shareAmount: share * netEstate,
        shareAmountPerHeir: count > 0 ? (share * netEstate) / count : 0,
        sharePercentagePerHeir: count > 0 ? (share * 100) / count : 0,
        isBlocked: isHeirBlocked,
        blockedBy: blocked[def.id],
        explanation: getDetailedExplanation(def.id, isHeirBlocked, share > 0, categoryMap[def.id], hasDescendant, activeHeirs[def.id], t),
        quranReference: getQuranRef(def.id),
        heirType: isHeirBlocked ? 'Blocked' : (categoryMap[def.id] as any || 'Sharer')
      });
    }
  });

  // Handle remaining residue (Radd or Treasury)
  const totalDistributed = results.reduce((sum, r) => sum + r.sharePercentage, 0);
  if (totalDistributed < 99.9 && netEstate > 0) {
    const remainingRatio = (100 - totalDistributed) / 100;
    results.push({
      heirId: 'governmentTreasury',
      heirName: t.heirs.governmentTreasury,
      count: 1,
      shareFraction: formatFraction(remainingRatio),
      sharePercentage: remainingRatio * 100,
      shareAmount: remainingRatio * netEstate,
      shareAmountPerHeir: remainingRatio * netEstate,
      sharePercentagePerHeir: remainingRatio * 100,
      isBlocked: false,
      explanation: t.exp_treasury,
      heirType: 'Treasury'
    });
  }

  return results;
};

const formatFraction = (val: number): string => {
  if (val < 1e-6) return '0';
  const denominators = [2, 3, 4, 6, 8, 12, 13, 15, 17, 24, 27, 32, 48];
  for (const d of denominators) {
    const n = Math.round(val * d);
    if (Math.abs(val - n / d) < 1e-3) return `${n}/${d}`;
  }
  return val.toFixed(3);
};

const getDetailedExplanation = (id: HeirKey, isBlocked: boolean, hasShare: boolean, type: string | undefined, hasDesc: boolean, count: number, t: any): string => {
  if (isBlocked) return t.exp_blocked;
  if (!hasShare) return t.exp_no_share;

  switch (id) {
    case 'husband': return hasDesc ? t.exp_husband_2 : t.exp_husband_1;
    case 'wife': return hasDesc ? t.exp_wife_2 : t.exp_wife_1;
    case 'son': return t.exp_son;
    case 'daughter':
      if (type === 'Residuary') return t.exp_daughter_3;
      return count === 1 ? t.exp_daughter_1 : t.exp_daughter_2;
    case 'father': return type === 'Sharer' ? t.exp_father_1 : t.exp_father_2;
    case 'mother': return hasDesc || count > 1 ? t.exp_mother_1 : t.exp_mother_2;
    default: return t.exp_general;
  }
};

const getQuranRef = (id: HeirKey): string => {
  const refs: Partial<Record<HeirKey, string>> = {
    son: '4:11', daughter: '4:11', father: '4:11', mother: '4:11',
    husband: '4:12', wife: '4:12', maternalBrother: '4:12', maternalSister: '4:12',
    fullSister: '4:176', paternalSister: '4:176'
  };
  return refs[id] || '';
};

import { HeirKey, CalculationResult, DeceasedGender, InheritanceState, FiqhSchool } from '../types';
import { ALL_HEIRS, i18nStrings } from '../constants';

export const calculateInheritance = (state: InheritanceState): CalculationResult[] => {
  const { 
    totalEstate, 
    funeralExpenses, 
    debts, 
    wasiyyat, 
    deceasedGender, 
    heirs, 
    school,
    language
  } = state;

  const t = i18nStrings[language] || i18nStrings.en;
  let results: CalculationResult[] = [];

  const deductions = (funeralExpenses || 0) + (debts || 0) + (wasiyyat || 0);
  const netEstate = Math.max(0, totalEstate - deductions);

  // Clean heirs based on gender logic
  const activeHeirs = { ...heirs };
  if (deceasedGender === DeceasedGender.Male) activeHeirs.husband = 0;
  if (deceasedGender === DeceasedGender.Female) activeHeirs.wife = 0;

  // Primary Heir Counts
  const nSon = activeHeirs.son || 0;
  const nDaughter = activeHeirs.daughter || 0;
  const nGrandson = activeHeirs.grandson || 0;
  const nGranddaughter = activeHeirs.granddaughter || 0;
  const nFather = activeHeirs.father || 0;
  const nMother = activeHeirs.mother || 0;
  const nGrandfather = activeHeirs.grandfather || 0;

  const nFullBro = activeHeirs.fullBrother || 0;
  const nFullSis = activeHeirs.fullSister || 0;
  const nPatBro = activeHeirs.paternalBrother || 0;
  const nPatSis = activeHeirs.paternalSister || 0;
  const nMatBro = activeHeirs.maternalBrother || 0;
  const nMatSis = activeHeirs.maternalSister || 0;

  const hasMaleDescendant = nSon > 0 || nGrandson > 0;
  const hasDescendant = hasMaleDescendant || nDaughter > 0 || nGranddaughter > 0;
  const sibCount = nFullBro + nFullSis + nPatBro + nPatSis + nMatBro + nMatSis;

  const blocked: Partial<Record<HeirKey, string>> = {};

  // --- 100% CORRECT HAJB (EXCLUSION) RULES ---

  // Son excludes...
  if (nSon > 0) {
    const label = t.heirs.son;
    blocked.grandson = label;
    blocked.granddaughter = label;
    ['fullBrother', 'fullSister', 'paternalBrother', 'paternalSister', 'maternalBrother', 'maternalSister', 
     'nephewFull', 'nephewPaternal', 'uncleFull', 'unclePaternal', 'cousinFull', 'cousinPaternal'].forEach(k => blocked[k as HeirKey] = label);
  }

  // Grandson excludes...
  if (nGrandson > 0 && !blocked.grandson) {
    const label = t.heirs.grandson;
    ['fullBrother', 'fullSister', 'paternalBrother', 'paternalSister', 'maternalBrother', 'maternalSister', 
     'nephewFull', 'nephewPaternal', 'uncleFull', 'unclePaternal', 'cousinFull', 'cousinPaternal'].forEach(k => blocked[k as HeirKey] = label);
  }

  // Father excludes...
  if (nFather > 0) {
    const label = t.heirs.father;
    blocked.grandfather = label;
    blocked.paternalGrandmother = label;
    ['fullBrother', 'fullSister', 'paternalBrother', 'paternalSister', 'maternalBrother', 'maternalSister', 
     'nephewFull', 'nephewPaternal', 'uncleFull', 'unclePaternal', 'cousinFull', 'cousinPaternal'].forEach(k => blocked[k as HeirKey] = label);
  }

  // Grandfather excludes...
  if (nGrandfather > 0 && !blocked.grandfather) {
    const label = t.heirs.grandfather;
    blocked.maternalBrother = label;
    blocked.maternalSister = label;
    // Hanafi difference
    if (school === FiqhSchool.Hanafi) {
      ['fullBrother', 'fullSister', 'paternalBrother', 'paternalSister'].forEach(k => blocked[k as HeirKey] = label);
    }
    // All schools: Grandfather blocks nephews and below
    ['nephewFull', 'nephewPaternal', 'uncleFull', 'unclePaternal', 'cousinFull', 'cousinPaternal'].forEach(k => blocked[k as HeirKey] = label);
  }

  // Mother excludes...
  if (nMother > 0) {
    const label = t.heirs.mother;
    blocked.paternalGrandmother = label;
    blocked.maternalGrandmother = label;
  }

  // Any descendant excludes maternal siblings
  if (hasDescendant) {
    const label = t.deceasedLabel; // Generic "Descendants exist"
    blocked.maternalBrother = label;
    blocked.maternalSister = label;
  }

  // Full Brother excludes...
  if (nFullBro > 0 && !blocked.fullBrother) {
    const label = t.heirs.fullBrother;
    ['paternalBrother', 'paternalSister', 'nephewFull', 'nephewPaternal', 'uncleFull', 'unclePaternal', 'cousinFull', 'cousinPaternal'].forEach(k => blocked[k as HeirKey] = label);
  }

  // Full Sister (as Residuary with Daughter) excludes...
  if (!blocked.fullSister && nFullSis > 0 && nDaughter > 0 && nSon === 0 && nFather === 0) {
    const label = t.heirs.fullSister;
    ['paternalBrother', 'paternalSister', 'nephewFull', 'nephewPaternal', 'uncleFull', 'unclePaternal', 'cousinFull', 'cousinPaternal'].forEach(k => blocked[k as HeirKey] = label);
  }

  // Paternal Brother excludes...
  if (nPatBro > 0 && !blocked.paternalBrother) {
    const label = t.heirs.paternalBrother;
    ['nephewFull', 'nephewPaternal', 'uncleFull', 'unclePaternal', 'cousinFull', 'cousinPaternal'].forEach(k => blocked[k as HeirKey] = label);
  }

  // Nephews and beyond...
  if (activeHeirs.nephewFull > 0 && !blocked.nephewFull) {
    const label = t.heirs.nephewFull;
    ['nephewPaternal', 'uncleFull', 'unclePaternal', 'cousinFull', 'cousinPaternal'].forEach(k => blocked[k as HeirKey] = label);
  }
  if (activeHeirs.nephewPaternal > 0 && !blocked.nephewPaternal) {
    const label = t.heirs.nephewPaternal;
    ['uncleFull', 'unclePaternal', 'cousinFull', 'cousinPaternal'].forEach(k => blocked[k as HeirKey] = label);
  }
  if (activeHeirs.uncleFull > 0 && !blocked.uncleFull) {
    const label = t.heirs.uncleFull;
    ['unclePaternal', 'cousinFull', 'cousinPaternal'].forEach(k => blocked[k as HeirKey] = label);
  }
  if (activeHeirs.unclePaternal > 0 && !blocked.unclePaternal) {
    const label = t.heirs.unclePaternal;
    ['cousinFull', 'cousinPaternal'].forEach(k => blocked[k as HeirKey] = label);
  }

  // --- SHARE CALCULATION (FURUD) ---
  let shares: Partial<Record<HeirKey, number>> = {};
  const catMap: Partial<Record<HeirKey, 'Sharer' | 'Residuary' | 'Treasury'>> = {};
  let totalF = 0;

  // Husband/Wife
  if (activeHeirs.husband > 0) {
    shares.husband = hasDescendant ? 1/4 : 1/2;
    catMap.husband = 'Sharer';
    totalF += shares.husband;
  }
  if (activeHeirs.wife > 0) {
    shares.wife = hasDescendant ? 1/8 : 1/4;
    catMap.wife = 'Sharer';
    totalF += shares.wife;
  }

  // Parents
  if (nMother > 0 && !blocked.mother) {
    shares.mother = (hasDescendant || sibCount >= 2) ? 1/6 : 1/3;
    // Umariyyatain rule (Special Case for Shafi'i/Hanafi/etc)
    const isUmariyyatain = (activeHeirs.husband > 0 || activeHeirs.wife > 0) && nFather > 0 && nMother > 0 && !hasDescendant && sibCount === 0;
    if (isUmariyyatain) {
       // Mother gets 1/3 of remainder
       const rem = 1 - (shares.husband || shares.wife || 0);
       shares.mother = rem / 3;
    }
    catMap.mother = 'Sharer';
    totalF += shares.mother;
  }
  if (nFather > 0 && !blocked.father) {
    if (hasMaleDescendant) {
      shares.father = 1/6;
      catMap.father = 'Sharer';
      totalF += 1/6;
    }
  }

  // Daughters
  if (nDaughter > 0 && nSon === 0) {
    shares.daughter = nDaughter === 1 ? 1/2 : 2/3;
    catMap.daughter = 'Sharer';
    totalF += shares.daughter;
  }

  // Maternal Siblings
  if (!blocked.maternalBrother && nMatBro > 0) {
    shares.maternalBrother = (nMatBro + nMatSis === 1) ? 1/6 : 1/3;
    catMap.maternalBrother = 'Sharer';
    totalF += shares.maternalBrother;
  }
  if (!blocked.maternalSister && nMatSis > 0) {
    shares.maternalSister = (nMatBro + nMatSis === 1) ? 1/6 : 1/3;
    catMap.maternalSister = 'Sharer';
    totalF += shares.maternalSister;
  }

  // AWAL / RADD ADJUSTMENT
  if (totalF > 1) {
    const factor = totalF;
    Object.keys(shares).forEach(k => shares[k as HeirKey]! /= factor);
    totalF = 1;
  }

  // ASABA (RESIDUE)
  let residue = 1 - totalF;
  if (residue > 1e-7) {
    const asaba: HeirKey[] = [];
    if (nSon > 0) { asaba.push('son'); if (nDaughter > 0) asaba.push('daughter'); }
    else if (nGrandson > 0 && !blocked.grandson) { asaba.push('grandson'); if (nGranddaughter > 0) asaba.push('granddaughter'); }
    else if (nFather > 0 && !blocked.father && !hasMaleDescendant) { asaba.push('father'); }
    else if (nGrandfather > 0 && !blocked.grandfather && !hasMaleDescendant) { 
      // Non-Hanafi: Grandfather shares with siblings (simplified logic here)
      if (school !== FiqhSchool.Hanafi && (nFullBro > 0 || nFullSis > 0)) {
         asaba.push('grandfather', 'fullBrother'); if (nFullSis > 0) asaba.push('fullSister');
      } else {
         asaba.push('grandfather');
      }
    }
    else if (nFullBro > 0 && !blocked.fullBrother) { asaba.push('fullBrother'); if (nFullSis > 0) asaba.push('fullSister'); }
    else if (nFullSis > 0 && !blocked.fullSister && nDaughter > 0) { asaba.push('fullSister'); } // Sis with Daughter
    else if (nPatBro > 0 && !blocked.paternalBrother) { asaba.push('paternalBrother'); if (nPatSis > 0) asaba.push('paternalSister'); }

    if (asaba.length > 0) {
      let totalW = 0;
      asaba.forEach(k => {
        const gen = ALL_HEIRS.find(h => h.id === k)?.gender === 'M' ? 2 : 1;
        totalW += gen * (activeHeirs[k] || 1);
      });
      asaba.forEach(k => {
        const gen = ALL_HEIRS.find(h => h.id === k)?.gender === 'M' ? 2 : 1;
        const s = (residue * gen * (activeHeirs[k] || 1)) / totalW;
        shares[k] = (shares[k] || 0) + s;
        catMap[k] = 'Residuary';
      });
      residue = 0;
    }
  }

  // BUILD RESULTS
  ALL_HEIRS.forEach(def => {
    const count = activeHeirs[def.id] || 0;
    const isBlk = !!blocked[def.id];
    if (count > 0 || isBlk) {
      const s = shares[def.id] || 0;
      results.push({
        heirId: def.id,
        heirName: t.heirs[def.id],
        count,
        shareFraction: formatFraction(s),
        sharePercentage: s * 100,
        shareAmount: s * netEstate,
        shareAmountPerHeir: count > 0 ? (s * netEstate) / count : 0,
        sharePercentagePerHeir: count > 0 ? (s * 100) / count : 0,
        isBlocked: isBlk,
        blockedBy: blocked[def.id],
        explanation: getExplanation(def.id, isBlk, s > 0, catMap[def.id], hasDescendant, count, t),
        quranReference: getQuranRef(def.id),
        heirType: isBlk ? 'Blocked' : (catMap[def.id] || 'Sharer') as any
      });
    }
  });

  // Treasury if residue remains
  if (residue > 1e-7 && netEstate > 0) {
    results.push({
      heirId: 'governmentTreasury',
      heirName: t.heirs.governmentTreasury,
      count: 1,
      shareFraction: formatFraction(residue),
      sharePercentage: residue * 100,
      shareAmount: residue * netEstate,
      shareAmountPerHeir: residue * netEstate,
      sharePercentagePerHeir: residue * 100,
      isBlocked: false,
      explanation: t.exp_treasury,
      heirType: 'Treasury'
    });
  }

  return results;
};

const formatFraction = (v: number) => {
  if (v < 1e-6) return '0';
  const dens = [2, 3, 4, 6, 8, 12, 13, 15, 17, 24, 27, 32, 48];
  for (const d of dens) {
    const n = Math.round(v * d);
    if (Math.abs(v - n / d) < 1e-3) return `${n}/${d}`;
  }
  return v.toFixed(3);
};

const getExplanation = (id: string, blk: boolean, hasS: boolean, type: any, hasD: boolean, c: number, t: any) => {
  if (blk) return t.exp_blocked;
  if (!hasS) return t.exp_no_share;
  if (id === 'son') return t.exp_son;
  if (id === 'daughter') return type === 'Residuary' ? t.exp_daughter_3 : (c === 1 ? t.exp_daughter_1 : t.exp_daughter_2);
  return t.exp_general;
};

const getQuranRef = (id: string) => {
  const rs: any = { son: '4:11', daughter: '4:11', father: '4:11', mother: '4:11', husband: '4:12', wife: '4:12' };
  return rs[id] || '';
};

import React, { useState, useMemo } from 'react';
import { 
  InheritanceState, 
  DeceasedGender, 
  FiqhSchool, 
  HeirKey 
} from './types';
import { 
  CURRENCIES, 
  LANGUAGES, 
  MALE_HEIRS, 
  FEMALE_HEIRS, 
  i18nStrings 
} from './constants';
import { calculateInheritance } from './logic/calculator';
import { FamilyTree } from './FamilyTree';
import { ResultExplanations } from './ResultExplanations';
import { 
  Calculator, Users, Globe, Landmark, 
  ArrowRight, RotateCcw, 
  Info, Network, Coins, MinusCircle, AlertTriangle, X, FileText, Download, ShieldCheck
} from 'lucide-react';

const HEIR_LIMITS: Record<string, number> = {
  husband: 1,
  wife: 4,
  father: 1,
  mother: 1,
  grandfather: 1,
  paternalGrandmother: 1,
  maternalGrandmother: 1
};

const DEFAULT_MAX_LIMIT = 100;

const App: React.FC = () => {
  const [state, setState] = useState<InheritanceState>({
    totalEstate: 0, 
    funeralExpenses: 0,
    debts: 0,
    wasiyyat: 0,
    currency: 'USD',
    deceasedGender: DeceasedGender.Male,
    school: FiqhSchool.Hanafi,
    language: 'en',
    heirs: {} as Record<HeirKey, number>
  });

  const [isCalculated, setIsCalculated] = useState(false);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);

  const t = i18nStrings[state.language] || i18nStrings.en;

  const sortedLanguages = useMemo(() => {
    return [...LANGUAGES].sort((a, b) => {
      if (a.code === state.language) return -1;
      if (b.code === state.language) return 1;
      return 0;
    });
  }, [state.language]);

  const formattedCurrencies = useMemo(() => {
    return [...CURRENCIES].map(c => {
      const localizedName = t.currencies[c.code] || c.nameEn;
      const displayLabel = state.language === 'en' 
        ? `${c.nameEn} (${c.symbol})`
        : `${localizedName} / ${c.nameEn} (${c.symbol})`;
      return { ...c, displayLabel };
    }).sort((a, b) => {
       if (a.code === state.currency) return -1;
       if (b.code === state.currency) return 1;
       return 0;
    });
  }, [state.currency, state.language, t.currencies]);

  // Reactive Results for Blocking Logic
  const results = useMemo(() => {
    return calculateInheritance(state);
  }, [state]);

  const blockedHeirIds = useMemo(() => {
    return new Set(results.filter(r => r.isBlocked).map(r => r.heirId));
  }, [results]);

  const triggerError = (msg: string) => {
    setErrorMessage(msg);
    setTimeout(() => setErrorMessage(null), 5000);
  };

  const resetAll = () => {
    setState({
      totalEstate: 0,
      funeralExpenses: 0,
      debts: 0,
      wasiyyat: 0,
      currency: state.currency,
      deceasedGender: state.deceasedGender,
      school: state.school,
      language: state.language,
      heirs: {} as Record<HeirKey, number>
    });
    setIsCalculated(false);
    setErrorMessage(null);
  };

  const handleHeirChange = (key: HeirKey, value: number) => {
    const max = HEIR_LIMITS[key] || DEFAULT_MAX_LIMIT;
    if (value > max) {
      triggerError(`Maximum limit for ${t.heirs?.[key] || key} is ${max}.`);
      return;
    }
    const val = Math.max(0, value);
    setState(prev => ({
      ...prev,
      heirs: { ...prev.heirs, [key]: val }
    }));
    // We don't force setIsCalculated(false) anymore to allow real-time blocking feedback
  };

  const handleNumericInput = (field: keyof InheritanceState, value: number) => {
    if (value < 0) return;
    if (field === 'totalEstate' && (value === 0 || isNaN(value))) {
      resetAll();
      return;
    }
    // Wasiyyat 1/3 Limit Check
    if (field === 'wasiyyat' && value > state.totalEstate / 3) {
       triggerError(t.wasiyyatLimit);
       return;
    }
    setState(prev => ({ ...prev, [field]: value }));
    setIsCalculated(false);
  };

  const handleExportPDF = () => {
    window.print();
  };

  const renderHeirInput = (h: any) => {
    if (h.id === 'husband' && state.deceasedGender === DeceasedGender.Male) return null;
    if (h.id === 'wife' && state.deceasedGender === DeceasedGender.Female) return null;

    const count = state.heirs[h.id] || 0;
    const isFilled = count > 0;
    const isBlocked = blockedHeirIds.has(h.id);
    const blocker = results.find(r => r.heirId === h.id)?.blockedBy;

    let containerClass = "p-4 md:p-5 rounded-[2rem] border-4 transition-all group relative overflow-hidden ";
    let labelClass = "block text-[10px] font-black uppercase mb-2 md:mb-3 leading-tight ";
    let inputClass = "w-full border-none rounded-xl text-lg md:text-2xl font-black py-2 md:py-3 px-3 md:px-5 outline-none transition-all shadow-inner ";

    if (isBlocked) {
      containerClass += "bg-red-50 border-red-500 shadow-lg shadow-red-100 scale-[0.98]";
      labelClass += "text-red-700";
      inputClass += "bg-white text-red-800 focus:ring-2 focus:ring-red-500 opacity-50 cursor-not-allowed";
    } else if (isFilled) {
      containerClass += "bg-green-50 border-green-500 shadow-lg shadow-green-100";
      labelClass += "text-green-700";
      inputClass += "bg-white text-green-700";
    } else {
      containerClass += "bg-slate-50 border-slate-50 hover:border-orange-200";
      labelClass += "text-slate-500";
      inputClass += "bg-white text-slate-800 focus:ring-2 focus:ring-orange-500";
    }

    const translatedName = t.heirs?.[h.id] || h.nameEn;
    const limitDisplay = HEIR_LIMITS[h.id] ? `(0-${HEIR_LIMITS[h.id]})` : `(0-100)`;

    return (
      <div key={h.id} className={containerClass}>
        <label className={labelClass}>
          {translatedName} {limitDisplay}
          {isBlocked && blocker && (
            <span className="block text-[8px] mt-1 font-black text-red-600 animate-pulse">
              {t.blockedBy} {blocker}
            </span>
          )}
        </label>
        <input 
          type="number" 
          min="0" 
          value={isBlocked ? '' : (count || '')}
          placeholder="0"
          disabled={isBlocked}
          onChange={(e) => handleHeirChange(h.id, Number(e.target.value))}
          className={inputClass}
        />
      </div>
    );
  };

  return (
    <div className="min-h-screen pb-20 px-4 md:px-8 bg-slate-50 text-slate-900 font-black">
      {errorMessage && (
        <div className="fixed top-8 left-1/2 -translate-x-1/2 z-[9999] animate-in slide-in-from-top-4 duration-300 w-full max-w-md px-4">
          <div className="bg-red-600 text-white p-5 rounded-[2rem] shadow-2xl flex items-center justify-between gap-4 border-4 border-red-400">
            <div className="flex items-center gap-3">
              <AlertTriangle className="shrink-0" />
              <p className="font-black text-sm md:text-base leading-tight">{errorMessage}</p>
            </div>
            <button onClick={() => setErrorMessage(null)} className="hover:bg-red-700 p-2 rounded-full transition-colors">
              <X size={20} />
            </button>
          </div>
        </div>
      )}

      <header className="max-w-7xl mx-auto py-8 flex flex-col md:flex-row justify-between items-center gap-6 no-print">
        <div className="flex items-center gap-4">
          <div className="bg-orange-600 p-4 rounded-3xl shadow-xl transition-transform hover:scale-105 active:scale-95 cursor-pointer">
            <Landmark className="text-white w-9 h-9" />
          </div>
          <div>
            <h1 className="text-4xl font-black tracking-tighter font-arabic leading-none">{t.title}</h1>
            <p className="text-orange-600 text-[10px] font-black uppercase tracking-[0.4em] mt-1.5">{t.subtitle}</p>
          </div>
        </div>

        <div className="grid grid-cols-2 md:flex items-center gap-3 w-full md:w-auto">
          <div className="flex items-center gap-2 bg-white p-3 rounded-2xl shadow-sm border border-slate-200">
            <Coins size={18} className="text-emerald-600 shrink-0" />
            <select 
              value={state.currency} 
              onChange={(e) => setState({...state, currency: e.target.value})}
              className="bg-transparent border-none text-[10px] md:text-sm font-black focus:ring-0 w-full cursor-pointer pr-4"
            >
              {formattedCurrencies.map(c => (
                <option key={c.code} value={c.code} className="font-sans">
                  {c.displayLabel}
                </option>
              ))}
            </select>
          </div>

          <div className="flex items-center gap-2 bg-white p-3 rounded-2xl shadow-sm border border-slate-200">
            <Globe size={18} className="text-blue-500 shrink-0" />
            <select 
              value={state.language} 
              onChange={(e) => setState({...state, language: e.target.value})}
              className="bg-transparent border-none text-[10px] md:text-sm font-black focus:ring-0 w-full cursor-pointer pr-4"
            >
              {sortedLanguages.map(l => <option key={l.code} value={l.code} className="font-sans">{l.name}</option>)}
