export default App;

import { HeirKey, CalculationResult, DeceasedGender, InheritanceState, FiqhSchool } from '../types';
import { ALL_HEIRS, i18nStrings } from '../constants';

export const calculateInheritance = (state: InheritanceState): CalculationResult[] => {
  const { 
    totalEstate, 
    funeralExpenses, 
    debts, 
    wasiyyat, 
    deceasedGender, 
    heirs, 
    school,
    language
  } = state;

  const t = i18nStrings[language] || i18nStrings.en;
  let results: CalculationResult[] = [];

  const deductions = (funeralExpenses || 0) + (debts || 0) + (wasiyyat || 0);
  const netEstate = Math.max(0, totalEstate - deductions);

  // Clean heirs based on gender logic
  const activeHeirs = { ...heirs };
  if (deceasedGender === DeceasedGender.Male) activeHeirs.husband = 0;
  if (deceasedGender === DeceasedGender.Female) activeHeirs.wife = 0;

  // Primary Heir Counts
  const nSon = activeHeirs.son || 0;
  const nDaughter = activeHeirs.daughter || 0;
  const nGrandson = activeHeirs.grandson || 0;
  const nGranddaughter = activeHeirs.granddaughter || 0;
  const nFather = activeHeirs.father || 0;
  const nMother = activeHeirs.mother || 0;
  const nGrandfather = activeHeirs.grandfather || 0;

  const nFullBro = activeHeirs.fullBrother || 0;
  const nFullSis = activeHeirs.fullSister || 0;
  const nPatBro = activeHeirs.paternalBrother || 0;
  const nPatSis = activeHeirs.paternalSister || 0;
  const nMatBro = activeHeirs.maternalBrother || 0;
  const nMatSis = activeHeirs.maternalSister || 0;

  const hasMaleDescendant = nSon > 0 || nGrandson > 0;
  const hasDescendant = hasMaleDescendant || nDaughter > 0 || nGranddaughter > 0;
  const sibCount = nFullBro + nFullSis + nPatBro + nPatSis + nMatBro + nMatSis;

  const blocked: Partial<Record<HeirKey, string>> = {};

  // --- 100% CORRECT HAJB (EXCLUSION) RULES ---
  const sonLabel = t.heirs.son;
  const fatherLabel = t.heirs.father;
  const motherLabel = t.heirs.mother;
  const gsLabel = t.heirs.grandson;
  const gfLabel = t.heirs.grandfather;
  const fbLabel = t.heirs.fullBrother;
  const pbLabel = t.heirs.paternalBrother;

  // Son Exclusions: Blocks grandsons, brothers, sisters, nephews, uncles, cousins.
  if (nSon > 0) {
    blocked.grandson = sonLabel;
    blocked.granddaughter = sonLabel;
    ['fullBrother', 'fullSister', 'paternalBrother', 'paternalSister', 'maternalBrother', 'maternalSister', 
     'nephewFull', 'nephewPaternal', 'uncleFull', 'unclePaternal', 'cousinFull', 'cousinPaternal'].forEach(k => blocked[k as HeirKey] = sonLabel);
  }

  // Grandson Exclusions: Same as son, but grandson is lower priority.
  if (nGrandson > 0 && !blocked.grandson) {
    ['fullBrother', 'fullSister', 'paternalBrother', 'paternalSister', 'maternalBrother', 'maternalSister', 
     'nephewFull', 'nephewPaternal', 'uncleFull', 'unclePaternal', 'cousinFull', 'cousinPaternal'].forEach(k => blocked[k as HeirKey] = gsLabel);
  }

  // Father Exclusions: Blocks grandfather, paternal grandmother, and collaterals.
  if (nFather > 0) {
    blocked.grandfather = fatherLabel;
    blocked.paternalGrandmother = fatherLabel;
    ['fullBrother', 'fullSister', 'paternalBrother', 'paternalSister', 'maternalBrother', 'maternalSister', 
     'nephewFull', 'nephewPaternal', 'uncleFull', 'unclePaternal', 'cousinFull', 'cousinPaternal'].forEach(k => blocked[k as HeirKey] = fatherLabel);
  }

  // Grandfather Exclusions: Blocks maternal siblings and lower branches.
  if (nGrandfather > 0 && !blocked.grandfather) {
    blocked.maternalBrother = gfLabel;
    blocked.maternalSister = gfLabel;
    if (school === FiqhSchool.Hanafi) {
      ['fullBrother', 'fullSister', 'paternalBrother', 'paternalSister'].forEach(k => blocked[k as HeirKey] = gfLabel);
    }
    ['nephewFull', 'nephewPaternal', 'uncleFull', 'unclePaternal', 'cousinFull', 'cousinPaternal'].forEach(k => blocked[k as HeirKey] = gfLabel);
  }

  // Mother Exclusions: Blocks grandmothers.
  if (nMother > 0) {
    blocked.paternalGrandmother = motherLabel;
    blocked.maternalGrandmother = motherLabel;
  }

  // Descendants exclude maternal siblings.
  if (hasDescendant) {
    const descLabel = t.deceasedLabel;
    blocked.maternalBrother = descLabel;
    blocked.maternalSister = descLabel;
  }

  // Full Brother Exclusions: Blocks paternal collaterals.
  if (nFullBro > 0 && !blocked.fullBrother) {
    ['paternalBrother', 'paternalSister', 'nephewFull', 'nephewPaternal', 'uncleFull', 'unclePaternal', 'cousinFull', 'cousinPaternal'].forEach(k => blocked[k as HeirKey] = fbLabel);
  }

  // Full Sister (as Residuary with Daughter) excludes paternal siblings.
  if (!blocked.fullSister && nFullSis > 0 && nDaughter > 0 && nSon === 0 && nFather === 0) {
    const fsLabel = t.heirs.fullSister;
    ['paternalBrother', 'paternalSister', 'nephewFull', 'nephewPaternal', 'uncleFull', 'unclePaternal', 'cousinFull', 'cousinPaternal'].forEach(k => blocked[k as HeirKey] = fsLabel);
  }

  // Paternal Brother Exclusions.
  if (nPatBro > 0 && !blocked.paternalBrother) {
    ['nephewFull', 'nephewPaternal', 'uncleFull', 'unclePaternal', 'cousinFull', 'cousinPaternal'].forEach(k => blocked[k as HeirKey] = pbLabel);
  }

  // Lower branch exclusions (Nephews, Uncles, Cousins).
  if (activeHeirs.nephewFull > 0 && !blocked.nephewFull) {
    const label = t.heirs.nephewFull;
    ['nephewPaternal', 'uncleFull', 'unclePaternal', 'cousinFull', 'cousinPaternal'].forEach(k => blocked[k as HeirKey] = label);
  }
  if (activeHeirs.nephewPaternal > 0 && !blocked.nephewPaternal) {
    const label = t.heirs.nephewPaternal;
    ['uncleFull', 'unclePaternal', 'cousinFull', 'cousinPaternal'].forEach(k => blocked[k as HeirKey] = label);
  }
  if (activeHeirs.uncleFull > 0 && !blocked.uncleFull) {
    const label = t.heirs.uncleFull;
    ['unclePaternal', 'cousinFull', 'cousinPaternal'].forEach(k => blocked[k as HeirKey] = label);
  }
  if (activeHeirs.unclePaternal > 0 && !blocked.unclePaternal) {
    const label = t.heirs.unclePaternal;
    ['cousinFull', 'cousinPaternal'].forEach(k => blocked[k as HeirKey] = label);
  }

  // --- SHARE CALCULATION (FURUD) ---
  let shares: Partial<Record<HeirKey, number>> = {};
  const catMap: Partial<Record<HeirKey, 'Sharer' | 'Residuary' | 'Treasury'>> = {};
  let totalF = 0;

  // Husband/Wife
  if (activeHeirs.husband > 0) {
    shares.husband = hasDescendant ? 1/4 : 1/2;
    catMap.husband = 'Sharer';
    totalF += shares.husband;
  }
  if (activeHeirs.wife > 0) {
    shares.wife = hasDescendant ? 1/8 : 1/4;
    catMap.wife = 'Sharer';
    totalF += shares.wife;
  }

  // Parents
  if (nMother > 0 && !blocked.mother) {
    shares.mother = (hasDescendant || sibCount >= 2) ? 1/6 : 1/3;
    const isUmariyyatain = (activeHeirs.husband > 0 || activeHeirs.wife > 0) && nFather > 0 && nMother > 0 && !hasDescendant && sibCount === 0;
    if (isUmariyyatain) {
       const rem = 1 - (shares.husband || shares.wife || 0);
       shares.mother = rem / 3;
    }
    catMap.mother = 'Sharer';
    totalF += shares.mother;
  }
  if (nFather > 0 && !blocked.father && hasMaleDescendant) {
    shares.father = 1/6;
    catMap.father = 'Sharer';
    totalF += 1/6;
  }

  // Daughters
  if (nDaughter > 0 && nSon === 0) {
    shares.daughter = nDaughter === 1 ? 1/2 : 2/3;
    catMap.daughter = 'Sharer';
    totalF += shares.daughter;
  }

  // Maternal Siblings
  if (!blocked.maternalBrother && nMatBro > 0) {
    shares.maternalBrother = (nMatBro + nMatSis === 1) ? 1/6 : 1/3;
    catMap.maternalBrother = 'Sharer';
    totalF += shares.maternalBrother;
  }
  if (!blocked.maternalSister && nMatSis > 0) {
    shares.maternalSister = (nMatBro + nMatSis === 1) ? 1/6 : 1/3;
    catMap.maternalSister = 'Sharer';
    totalF += shares.maternalSister;
  }

  // Awal adjustment
  if (totalF > 1) {
    const factor = totalF;
    Object.keys(shares).forEach(k => shares[k as HeirKey]! /= factor);
    totalF = 1;
  }

  // Residue (Asaba)
  let residue = 1 - totalF;
  if (residue > 1e-7) {
    const asaba: HeirKey[] = [];
    if (nSon > 0) { asaba.push('son'); if (nDaughter > 0) asaba.push('daughter'); }
    else if (nGrandson > 0 && !blocked.grandson) { asaba.push('grandson'); if (nGranddaughter > 0) asaba.push('granddaughter'); }
    else if (nFather > 0 && !blocked.father && !hasMaleDescendant) { asaba.push('father'); }
    else if (nGrandfather > 0 && !blocked.grandfather && !hasMaleDescendant) { asaba.push('grandfather'); }
    else if (nFullBro > 0 && !blocked.fullBrother) { asaba.push('fullBrother'); if (nFullSis > 0) asaba.push('fullSister'); }
    else if (nPatBro > 0 && !blocked.paternalBrother) { asaba.push('paternalBrother'); if (nPatSis > 0) asaba.push('paternalSister'); }

    if (asaba.length > 0) {
      let totalW = 0;
      asaba.forEach(k => {
        const gen = ALL_HEIRS.find(h => h.id === k)?.gender === 'M' ? 2 : 1;
        totalW += gen * (activeHeirs[k] || 1);
      });
      asaba.forEach(k => {
        const gen = ALL_HEIRS.find(h => h.id === k)?.gender === 'M' ? 2 : 1;
        const s = (residue * gen * (activeHeirs[k] || 1)) / totalW;
        shares[k] = (shares[k] || 0) + s;
        catMap[k] = 'Residuary';
      });
      residue = 0;
    }
  }

  // Finalizing Results
  ALL_HEIRS.forEach(def => {
    const count = activeHeirs[def.id] || 0;
    const isBlk = !!blocked[def.id];
    if (count > 0 || isBlk) {
      const s = shares[def.id] || 0;
      results.push({
        heirId: def.id,
        heirName: t.heirs[def.id],
        count,
        shareFraction: formatFraction(s),
        sharePercentage: s * 100,
        shareAmount: s * netEstate,
        shareAmountPerHeir: count > 0 ? (s * netEstate) / count : 0,
        sharePercentagePerHeir: count > 0 ? (s * 100) / count : 0,
        isBlocked: isBlk,
        blockedBy: blocked[def.id],
        explanation: constructExplanation(def.id, isBlk, s > 0, catMap[def.id], hasDescendant, count, nSon, nFather, sibCount, t),
        quranReference: getQuranRef(def.id),
        heirType: isBlk ? 'Blocked' : (catMap[def.id] || 'Sharer') as any
      });
    }
  });

  if (residue > 1e-7 && netEstate > 0) {
    results.push({
      heirId: 'governmentTreasury',
      heirName: t.heirs.governmentTreasury,
      count: 1,
      shareFraction: formatFraction(residue),
      sharePercentage: residue * 100,
      shareAmount: residue * netEstate,
      shareAmountPerHeir: residue * netEstate,
      sharePercentagePerHeir: residue * 100,
      isBlocked: false,
      explanation: t.exp_treasury,
      heirType: 'Treasury'
    });
  }

  return results;
};

const formatFraction = (v: number) => {
  if (v < 1e-6) return '0';
  const dens = [2, 3, 4, 6, 8, 12, 13, 15, 17, 24, 27, 32, 48, 72, 96];
  for (const d of dens) {
    const n = Math.round(v * d);
    if (Math.abs(v - n / d) < 1e-4) return `${n}/${d}`;
  }
  return v.toFixed(3);
};

const constructExplanation = (id: string, isBlocked: boolean, hasShare: boolean, type: string | undefined, hasDesc: boolean, count: number, nSon: number, nFather: number, sibCount: number, t: any): string => {
  if (isBlocked) return `This heir is excluded from the inheritance because the ${t.blockedBy} exists. In Islamic Fiqh, closer relatives prevent more distant ones.`;
  if (!hasShare) return t.exp_no_share;

  if (type === 'Residuary') {
    if (id === 'son') return "Acts as Asaba (Residuary) as the primary male descendant; takes the entire remaining estate after fixed sharers have been paid.";
    if (id === 'daughter') return "Receives a share of the residue alongside her brother(s) in a 2:1 ratio (male to female).";
    if (id === 'father') return "Receives the remaining residue as the primary male ascendant because there are no male descendants to prevent him.";
    if (id === 'fullBrother') return "Acts as Asaba (Residuary) as the nearest male collateral relative, taking the balance after fixed portions are distributed.";
    return "This heir takes the remaining residue (Asaba) as the next of kin in the inheritance hierarchy.";
  }

  switch (id) {
    case 'husband': return hasDesc ? "Gets 1/4 because the deceased left behind children or grandchildren." : "Gets 1/2 because the deceased left behind no children or grandchildren.";
    case 'wife': return hasDesc ? "Gets 1/8 because the deceased left behind children or grandchildren." : "Gets 1/4 because the deceased left behind no children or grandchildren.";
    case 'mother': return (hasDesc || sibCount >= 2) ? "Gets 1/6 due to the presence of descendants or multiple siblings." : "Gets 1/3 as a fixed sharer because there are no descendants and less than two siblings.";
    case 'father': return "Gets a fixed share of 1/6 because there is a male descendant (Son or Grandson) present.";
    case 'daughter': return count === 1 ? "Gets 1/2 as the only daughter when no son is present to make her a residuary." : "Gets 2/3 shared equally between daughters when no son is present.";
    case 'maternalBrother': 
    case 'maternalSister': return (count === 1) ? "Gets 1/6 as the only maternal sibling, provided no descendants or male ascendants are present." : "Share 1/3 equally between all maternal siblings regardless of gender.";
    default: return t.exp_general;
  }
};

const getQuranRef = (id: string) => {
  const rs: any = { 
    son: 'Surah An-Nisa, 4:11', 
    daughter: 'Surah An-Nisa, 4:11', 
    father: 'Surah An-Nisa, 4:11', 
    mother: 'Surah An-Nisa, 4:11', 
    husband: 'Surah An-Nisa, 4:12', 
    wife: 'Surah An-Nisa, 4:12', 
    maternalBrother: 'Surah An-Nisa, 4:12', 
    maternalSister: 'Surah An-Nisa, 4:12', 
    fullSister: 'Surah An-Nisa, 4:176' 
  };
  return rs[id] || '';
};

import React, { useState, useMemo } from 'react';
import { 
  InheritanceState, 
  DeceasedGender, 
  FiqhSchool, 
  HeirKey 
} from './types';
import { 
  CURRENCIES, 
  LANGUAGES, 
  MALE_HEIRS, 
  FEMALE_HEIRS, 
  i18nStrings 
} from './constants';
import { calculateInheritance } from './logic/calculator';
import { FamilyTree } from './FamilyTree';
import { ResultExplanations } from './ResultExplanations';
import { 
  Calculator, Users, Globe, Landmark, 
  ArrowRight, RotateCcw, 
  Info, Network, Coins, MinusCircle, AlertTriangle, X, FileText, Download, ShieldCheck
} from 'lucide-react';

const HEIR_LIMITS: Record<string, number> = {
  husband: 1,
  wife: 4,
  father: 1,
  mother: 1,
  grandfather: 1,
  paternalGrandmother: 1,
  maternalGrandmother: 1
};

const DEFAULT_MAX_LIMIT = 100;

const App: React.FC = () => {
  const [state, setState] = useState<InheritanceState>({
    totalEstate: 0, 
    funeralExpenses: 0,
    debts: 0,
    wasiyyat: 0,
    currency: 'USD',
    deceasedGender: DeceasedGender.Male,
    school: FiqhSchool.Hanafi,
    language: 'en',
    heirs: {} as Record<HeirKey, number>
  });

  const [isCalculated, setIsCalculated] = useState(false);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);

  const t = i18nStrings[state.language] || i18nStrings.en;

  const sortedLanguages = useMemo(() => {
    return [...LANGUAGES].sort((a, b) => {
      if (a.code === state.language) return -1;
      if (b.code === state.language) return 1;
      return 0;
    });
  }, [state.language]);

  const formattedCurrencies = useMemo(() => {
    return [...CURRENCIES].map(c => {
      const localizedName = t.currencies[c.code] || c.nameEn;
      const displayLabel = state.language === 'en' 
        ? `${c.nameEn} (${c.symbol})`
        : `${localizedName} / ${c.nameEn} (${c.symbol})`;
      return { ...c, displayLabel };
    }).sort((a, b) => {
       if (a.code === state.currency) return -1;
       if (b.code === state.currency) return 1;
       return 0;
    });
  }, [state.currency, state.language, t.currencies]);

  const results = useMemo(() => {
    return calculateInheritance(state);
  }, [state]);

  const blockedHeirIds = useMemo(() => {
    return new Set(results.filter(r => r.isBlocked).map(r => r.heirId));
  }, [results]);

  const triggerError = (msg: string) => {
    setErrorMessage(msg);
    setTimeout(() => setErrorMessage(null), 5000);
  };

  const resetAll = () => {
    setState({
      totalEstate: 0,
      funeralExpenses: 0,
      debts: 0,
      wasiyyat: 0,
      currency: state.currency,
      deceasedGender: state.deceasedGender,
      school: state.school,
      language: state.language,
      heirs: {} as Record<HeirKey, number>
    });
    setIsCalculated(false);
    setErrorMessage(null);
  };

  const handleHeirChange = (key: HeirKey, value: number) => {
    const max = HEIR_LIMITS[key] || DEFAULT_MAX_LIMIT;
    if (value > max) {
      triggerError(`Maximum limit for ${t.heirs?.[key] || key} is ${max}.`);
      return;
    }
    const val = Math.max(0, value);
    setState(prev => ({
      ...prev,
      heirs: { ...prev.heirs, [key]: val }
    }));
  };

  const handleNumericInput = (field: keyof InheritanceState, value: number) => {
    if (value < 0) return;
    if (field === 'totalEstate' && (value === 0 || isNaN(value))) {
      resetAll();
      return;
    }
    if (field === 'wasiyyat' && value > state.totalEstate / 3) {
       triggerError(t.wasiyyatLimit);
       return;
    }
    setState(prev => ({ ...prev, [field]: value }));
    setIsCalculated(false);
  };

  const handleExportPDF = () => {
    window.print();
  };

  const renderDeductionInput = (label: string, value: number, field: keyof InheritanceState) => (
    <div key={field}>
      <label className="block text-2xl font-black uppercase text-slate-400 mb-6 tracking-widest leading-tight">{label}</label>
      <div className="relative">
        <input 
          type="number" 
          value={value || ''} 
          placeholder="0"
          onChange={(e) => handleNumericInput(field, Number(e.target.value))}
          className={`w-full border-4 rounded-[2rem] py-5 md:py-7 px-6 md:px-10 font-black text-xl md:text-3xl outline-none transition-all placeholder-slate-300 shadow-inner ${value > 0 ? 'bg-red-50 border-red-500 text-red-700' : 'bg-slate-50 border-slate-100 focus:border-red-500'}`}
        />
        <div className="absolute right-6 md:right-10 top-1/2 -translate-y-1/2 font-black text-lg md:text-2xl opacity-60 pointer-events-none text-slate-400">
          {CURRENCIES.find(c => c.code === state.currency)?.symbol || '$'}
        </div>
      </div>
    </div>
  );

  const renderHeirInput = (h: any) => {
    if (h.id === 'husband' && state.deceasedGender === DeceasedGender.Male) return null;
    if (h.id === 'wife' && state.deceasedGender === DeceasedGender.Female) return null;

    const count = state.heirs[h.id] || 0;
    const isFilled = count > 0;
    const isBlocked = blockedHeirIds.has(h.id);
    const blocker = results.find(r => r.heirId === h.id)?.blockedBy;

    let containerClass = "p-5 md:p-8 rounded-[2.5rem] border-4 transition-all group relative overflow-hidden ";
    let labelClass = "block text-2xl font-black uppercase mb-4 md:mb-6 leading-tight ";
    let inputClass = "w-full border-none rounded-2xl text-xl md:text-3xl font-black py-4 md:py-5 px-6 md:px-8 outline-none transition-all shadow-inner ";

    if (isBlocked) {
      containerClass += "bg-red-50 border-red-500 shadow-lg shadow-red-100 scale-[0.98]";
      labelClass += "text-red-700";
      inputClass += "bg-white text-red-800 focus:ring-2 focus:ring-red-500 opacity-20 cursor-not-allowed";
    } else if (isFilled) {
      containerClass += "bg-green-50 border-green-500 shadow-lg shadow-green-100";
      labelClass += "text-green-700";
      inputClass += "bg-white text-green-700";
    } else {
      containerClass += "bg-slate-50 border-slate-50 hover:border-orange-200";
      labelClass += "text-slate-500";
      inputClass += "bg-white text-slate-800 focus:ring-2 focus:ring-orange-500";
    }

    const translatedName = t.heirs?.[h.id] || h.nameEn;
    const limitDisplay = HEIR_LIMITS[h.id] ? `(0-${HEIR_LIMITS[h.id]})` : `(0-100)`;

    return (
      <div key={h.id} className={containerClass}>
        <label className={labelClass}>
          {translatedName} <span className="text-xs font-bold opacity-60">{limitDisplay}</span>
        </label>
        <div className="relative">
          <input 
            type="number" 
            min="0" 
            value={isBlocked ? '' : (count || '')}
            placeholder={isBlocked ? '' : "0"}
            disabled={isBlocked}
            onChange={(e) => handleHeirChange(h.id, Number(e.target.value))}
            className={inputClass}
          />
          {isBlocked && (
            <div className="absolute inset-0 flex items-center justify-center px-4 pointer-events-none bg-white/40 backdrop-blur-[1px] rounded-2xl">
              <span className="text-red-600 font-black text-xs md:text-lg italic uppercase text-center leading-tight">
                {t.blockedBy} {blocker}
              </span>
            </div>
          )}
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen pb-20 px-4 md:px-8 bg-slate-50 text-slate-900 font-black">
      {errorMessage && (
        <div className="fixed top-8 left-1/2 -translate-x-1/2 z-[9999] animate-in slide-in-from-top-4 duration-300 w-full max-w-md px-4">
          <div className="bg-red-600 text-white p-6 rounded-[2.5rem] shadow-2xl flex items-center justify-between gap-6 border-4 border-red-400">
            <div className="flex items-center gap-4">
              <AlertTriangle className="shrink-0" size={32} />
              <p className="font-black text-base md:text-xl leading-tight">{errorMessage}</p>
            </div>
            <button onClick={() => setErrorMessage(null)} className="hover:bg-red-700 p-2 rounded-full transition-colors">
              <X size={24} />
            </button>
          </div>
        </div>
      )}

      <header className="max-w-7xl mx-auto py-12 flex flex-col md:flex-row justify-between items-center gap-8 no-print">
        <div className="flex items-center gap-6">
          <div className="bg-orange-600 p-6 rounded-[2.5rem] shadow-2xl transition-transform hover:scale-105 active:scale-95 cursor-pointer">
            <Landmark className="text-white w-12 h-12" />
          </div>
          <div>
            <h1 className="text-5xl md:text-6xl font-black tracking-tighter font-arabic leading-none">{t.title}</h1>
            <p className="text-orange-600 text-[12px] font-black uppercase tracking-[0.6em] mt-3">{t.subtitle}</p>
          </div>
        </div>

        <div className="grid grid-cols-2 md:flex items-center gap-4 w-full md:w-auto">
          <div className="flex items-center gap-3 bg-white p-4 rounded-3xl shadow-sm border border-slate-200">
            <Coins size={24} className="text-emerald-600 shrink-0" />
            <select 
              value={state.currency} 
              onChange={(e) => setState({...state, currency: e.target.value})}
              className="bg-transparent border-none text-sm md:text-lg font-black focus:ring-0 w-full cursor-pointer pr-6"
            >
              {formattedCurrencies.map(c => (
                <option key={c.code} value={c.code} className="font-sans">
                  {c.displayLabel}
                </option>
              ))}
            </select>
          </div>

          <div className="flex items-center gap-3 bg-white p-4 rounded-3xl shadow-sm border border-slate-200">
            <Globe size={24} className="text-blue-500 shrink-0" />
            <select 
              value={state.language} 
              onChange={(e) => setState({...state, language: e.target.value})}
              className="bg-transparent border-none text-sm md:text-lg font-black focus:ring-0 w-full cursor-pointer pr-6"
            >
              {sortedLanguages.map(l => <option key={l.code} value={l.code} className="font-sans">{l.name}</option>)}
            </select>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-10 md:gap-16">
        <div className="lg:col-span-5 space-y-12 no-print">
          <section className="bg-white p-8 md:p-14 rounded-[4rem] shadow-2xl shadow-slate-200/50 border border-slate-100">
            <h2 className="text-4xl font-black mb-12 flex items-center gap-6">
              <Calculator className="text-orange-600" size={40} />
              {t.summary}
            </h2>
            <div className="space-y-12">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div>
                  <label className="block text-2xl font-black uppercase text-slate-400 mb-6 tracking-widest">{t.distributionAmount}</label>
                  <div className="relative">
                    <input 
                      type="number" 
                      value={state.totalEstate || ''} 
                      placeholder="0"
                      onChange={(e) => handleNumericInput('totalEstate', Number(e.target.value))}
                      className={`w-full border-4 rounded-[2.5rem] py-5 md:py-8 px-8 md:px-12 font-black text-2xl md:text-4xl outline-none transition-all placeholder-slate-300 shadow-inner ${state.totalEstate > 0 ? 'bg-green-50 border-green-500 text-green-700' : 'bg-slate-50 border-slate-100 focus:border-orange-500'}`}
                    />
                    <div className="absolute right-8 md:right-12 top-1/2 -translate-y-1/2 font-black text-xl md:text-3xl opacity-60 pointer-events-none text-slate-400">
                      {CURRENCIES.find(c => c.code === state.currency)?.symbol || '$'}
                    </div>
                  </div>
                </div>

                <div>
                  <label className="block text-2xl font-black uppercase text-slate-400 mb-6 tracking-widest">{t.fiqhSchool}</label>
                  <select 
                    value={state.school} 
                    onChange={(e) => {
                      setState({...state, school: e.target.value as FiqhSchool});
                      setIsCalculated(false);
                    }}
                    className="w-full h-[76px] md:h-[104px] bg-slate-50 border-none rounded-[2.5rem] px-8 md:px-12 font-black text-lg md:text-2xl focus:ring-4 focus:ring-orange-500 transition-all cursor-pointer"
                  >
                    {Object.values(FiqhSchool).map(s => <option key={s} value={s}>{t.schools[s] || s}</option>)}
                  </select>
                </div>
              </div>

              <div>
                <label className="block text-2xl font-black uppercase text-slate-400 mb-6 tracking-widest">{t.deceasedGender}</label>
                <div className="flex p-3 bg-slate-100 rounded-[3rem] border-4 border-slate-200">
                  <button 
                    onClick={() => {
                      setState({...state, deceasedGender: DeceasedGender.Male, heirs: {} as any});
                      setIsCalculated(false);
                    }}
                    className={`flex-1 py-4 md:py-7 text-lg md:text-2xl font-black rounded-[2.5rem] transition-all ${state.deceasedGender === DeceasedGender.Male ? 'bg-orange-600 shadow-2xl text-white scale-[1.03]' : 'text-slate-400 hover:text-slate-600'}`}
                  >
                    {t.male}
                  </button>
                  <button 
                    onClick={() => {
                      setState({...state, deceasedGender: DeceasedGender.Female, heirs: {} as any});
                      setIsCalculated(false);
                    }}
                    className={`flex-1 py-4 md:py-7 text-lg md:text-2xl font-black rounded-[2.5rem] transition-all ${state.deceasedGender === DeceasedGender.Female ? 'bg-orange-600 shadow-2xl text-white scale-[1.03]' : 'text-slate-400 hover:text-slate-600'}`}
                  >
                    {t.female}
                  </button>
                </div>
              </div>
            </div>
          </section>

          <section className="bg-white p-8 md:p-14 rounded-[4rem] shadow-2xl shadow-slate-200/50 border border-slate-100">
            <h2 className="text-4xl font-black mb-12 flex items-center gap-6">
              <MinusCircle className="text-red-500" size={40} />
              {t.deductions}
            </h2>
            <div className="space-y-12">
              {renderDeductionInput(t.funeralExpenses, state.funeralExpenses, 'funeralExpenses')}
              {renderDeductionInput(t.debts, state.debts, 'debts')}
              {renderDeductionInput(t.wasiyyat, state.wasiyyat, 'wasiyyat')}
            </div>
          </section>

          <section className="bg-white p-8 md:p-14 rounded-[4rem] shadow-2xl shadow-slate-200/50 border border-slate-100">
            <h2 className="text-4xl font-black mb-12 flex items-center gap-6">
              <Users className="text-orange-600" size={40} />
              {t.heirsSelection}
            </h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8 md:gap-10">
              {MALE_HEIRS.filter(h => h.id === 'husband').map(renderHeirInput)}
              {FEMALE_HEIRS.filter(h => h.id === 'wife').map(renderHeirInput)}
              {[...MALE_HEIRS, ...FEMALE_HEIRS]
                .filter(h => h.id !== 'husband' && h.id !== 'wife' && h.id !== 'freedSlaveMale' && h.id !== 'freedSlaveFemale')
                .map(renderHeirInput)}
            </div>
          </section>

          <div className="flex flex-col sm:flex-row gap-6 md:gap-8">
            <button 
              onClick={() => setIsCalculated(true)}
              className="flex-[2] bg-orange-600 hover:bg-orange-700 text-white font-black py-6 md:py-10 px-8 md:px-14 rounded-[3rem] shadow-3xl shadow-orange-500/40 transition-all flex items-center justify-center gap-5 group active:scale-95"
            >
              <span className="text-xl md:text-3xl">{t.calculate}</span>
              <ArrowRight size={40} className="group-hover:translate-x-5 transition-transform" />
            </button>
            <button 
              onClick={resetAll}
              className="flex-1 bg-slate-800 hover:bg-slate-900 text-white font-black py-6 md:py-10 px-8 md:px-14 rounded-[3rem] shadow-3xl shadow-slate-900/40 transition-all flex items-center justify-center gap-5 group active:scale-95"
            >
              <RotateCcw size={32} className="group-hover:rotate-180 transition-transform duration-700" />
              <span className="text-xl md:text-2xl">{t.reset}</span>
            </button>
          </div>
        </div>

        <div className="lg:col-span-7 space-y-16">
          {!isCalculated ? (
            <div className="bg-white border-8 border-dashed border-slate-200 rounded-[5rem] p-16 md:p-32 flex flex-col items-center text-center no-print">
              <div className="bg-orange-50 p-14 rounded-full mb-12 shadow-inner">
                <Info size={100} className="text-orange-200" />
              </div>
              <h3 className="text-4xl md:text-5xl font-black text-slate-800 mb-6">{t.results}</h3>
              <p className="text-slate-400 max-w-sm text-xl md:text-2xl font-bold leading-relaxed">{t.noHeirs}</p>
            </div>
          ) : (
            <div className="space-y-16 animate-in fade-in slide-in-from-bottom-16 duration-700 print-container">
              <div className="bg-white p-10 md:p-16 rounded-[4rem] shadow-3xl border border-slate-100 overflow-hidden page-break-after">
                <div className="print-only mb-16 text-center border-b-8 border-orange-600 pb-12">
                  <h1 className="text-6xl font-black font-arabic">{t.title}</h1>
                  <p className="text-orange-600 text-[14px] font-black uppercase tracking-[0.8em] mt-4">{t.subtitle}</p>
                </div>

                <div className="flex justify-between items-center mb-16">
                  <h2 className="text-5xl font-black flex items-center gap-6">
                    <span className="w-3 h-12 bg-orange-600 rounded-full block"></span>
                    {t.results}
                  </h2>
                </div>

                <div className="space-y-12">
                  <div className="bg-gradient-to-br from-slate-900 to-slate-800 p-12 md:p-20 rounded-[4rem] shadow-4xl text-white flex flex-col md:flex-row justify-between items-center gap-10">
                    <div className="w-full md:w-auto text-center md:text-left">
                      <p className="text-2xl font-black uppercase mb-4 tracking-widest opacity-80">{t.distributionAmount}</p>
                      <p className="text-7xl md:text-9xl font-black flex items-baseline justify-center md:justify-start gap-4">
                        {state.totalEstate.toLocaleString()}
                        <span className="text-3xl font-bold opacity-70">{state.currency}</span>
                      </p>
                      {(state.funeralExpenses > 0 || state.debts > 0 || state.wasiyyat > 0) && (
                        <div className="mt-10 space-y-3 bg-white/10 p-8 rounded-[2.5rem] backdrop-blur-md">
                           <p className="text-lg font-bold opacity-80">{t.totalDeductionsLabel}: {(state.funeralExpenses + state.debts + state.wasiyyat).toLocaleString()} {state.currency}</p>
                           <p className="text-2xl font-black text-emerald-400">{t.netEstateLabel}: {(state.totalEstate - (state.funeralExpenses + state.debts + state.wasiyyat)).toLocaleString()} {state.currency}</p>
                        </div>
                      )}
                    </div>
                  </div>
                </div>
              </div>

              <div className="bg-white p-10 md:p-16 rounded-[4rem] shadow-3xl border border-slate-100 page-break-before page-break-after">
                <h2 className="text-4xl font-black mb-16 flex items-center gap-6">
                  <Network className="text-blue-500" size={40} />
                  {t.familyTree}
                </h2>
                <FamilyTree results={results} deceasedGender={state.deceasedGender} currency={state.currency} language={state.language} />
              </div>

              <div className="page-break-before">
                <ResultExplanations results={results} t={t} />
              </div>

              <div className="mt-20 space-y-12 no-print">
                <div className="bg-gradient-to-r from-emerald-600 to-teal-700 p-14 md:p-24 rounded-[5rem] text-white shadow-4xl flex flex-col items-center text-center group">
                  <div className="bg-white/20 p-10 rounded-full mb-12 backdrop-blur-xl group-hover:scale-110 transition-transform">
                    <FileText size={100} className="text-white" />
                  </div>
                  <h3 className="text-5xl font-black mb-6">Download Formal Report</h3>
                  <p className="text-emerald-100 font-bold max-w-2xl mb-16 text-2xl leading-relaxed">
                    Generate a high-resolution PDF calculation report including the family tree and Al-Farā’iḍ justifications. Perfect for documentation and verification with Islamic authorities.
                  </p>
                  <button 
                    onClick={handleExportPDF}
                    className="bg-white text-emerald-700 hover:bg-emerald-50 font-black py-8 px-20 rounded-full shadow-4xl transition-all flex items-center gap-6 text-3xl active:scale-95"
                  >
                    <Download size={48} />
                    Export PDF
                  </button>
                  <div className="mt-12 flex items-center gap-4 opacity-70 text-sm uppercase tracking-[0.4em] font-black">
                    <ShieldCheck size={24} />
                    Sharī‘ah Compliant Algorithms
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>
      </main>

      <footer className="max-w-7xl mx-auto mt-24 pt-16 border-t border-slate-200 text-center no-print pb-16">
        <p className="text-slate-400 text-lg font-black tracking-[0.4em] uppercase opacity-40">
          &copy; {new Date().getFullYear()} {t.title} • Al-Farā’iḍ Professional
        </p>
      </footer>
    </div>
  );
};

export default App;
